window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["p"]={"Piotr": "<b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Paweł": "Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "Patryk": "<b>Patryk</b> – oboczna, skrócona wersja imienia <a href=\"https://pl.wikipedia.org/wiki/Patrycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycjusz</a>, posiadającego też formę <a href=\"https://pl.wikipedia.org/wiki/Patrycy\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycy</a>. Pochodzenie i znaczenie: łacińskie: <i>patricius</i> – patrycjuszowski, szlachecki, szlachetnie urodzony, zasiadający w senacie. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Patrycja\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycja</a>.", "Przemysław": "<b>Przemysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało prawdopodobnie przez modyfikację <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <b><a href=\"https://pl.wikipedia.org/wiki/Przemys%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Przemysł</a></b>, kiedy świadomość jego pochodzenia zatarła się i błędnie zostało ono uznane za imię kończące się członem <i>-sław</i> (zamiast <i>-mysł</i>), aczkolwiek zdaniem <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Br%C3%BCckner\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Brücknera</a> imię Przemysław jest poprawne: pierwszy człon „przem” pochodzi od dawnego słowa „przem, przemy” – szczery, otwarty, prosty (stąd wywodzi się słowo uprzejmy); człon „przem” występuje też w imieniu Bezprzem, <a href=\"https://pl.wikipedia.org/wiki/Przezprzem\" target=\"_blank\" rel=\"noopener noreferrer\">Przezprzem</a>, <a href=\"https://pl.wikipedia.org/wiki/Bezprym\" target=\"_blank\" rel=\"noopener noreferrer\">Bezprym</a>. W Polsce imię to odnotowano po raz pierwszy w 1212 jako <i>Premizlaus</i>.", "Pavlo": "<p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Petro": "<p>Petro to męskie imię, nazwisko i starożytne rzymskie nazwisko. Może odnosić się do:</p>", "Peter": "<p>Peter (niemiecki Peter) - osobiste imię (variant nazwy Piote), nazwisko i nazwisko.</p>", "Patrick": "<p>Patrick (ang. Patrick) - męskie imię pochodzące od łacińskiego.</p>", "Paul": "<p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Philip": "<p>Filip (lat. - Philip ?</p>", "Patrycjusz": "<b>Patrycjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>patricius</i> oznaczającego „szlachetnie urodzony, patrycjuszowski”. Jego obocznymi wariantami są <a href=\"https://pl.wikipedia.org/wiki/Patrycy\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycy</a> i <a href=\"https://pl.wikipedia.org/wiki/Patryk\" target=\"_blank\" rel=\"noopener noreferrer\">Patryk</a>, a żeńskim odpowiednikiem – <a href=\"https://pl.wikipedia.org/wiki/Patrycja\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycja</a>.", "Pascal": "<p>Pascal - jeden z najbardziej znanych języków programowania, używany do nauczania programowania w wyższych klasach i na pierwszych kursach uczelni, jest podstawą dla szeregu innych języków.</p>", "Pablo": "<p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Platon": "Wzrost popularności myśli Platona oraz istotne postępy w badaniach nad jego tekstami zbiegały się z ważnymi przełomami w <a href=\"https://pl.wikipedia.org/wiki/Historia_filozofii_(nauka)\" target=\"_blank\" rel=\"noopener noreferrer\">historii filozofii i nauki</a>, szczególnie w okresie <a href=\"https://pl.wikipedia.org/wiki/Renesans\" target=\"_blank\" rel=\"noopener noreferrer\">renesansu</a> we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> oraz w <a href=\"https://pl.wikipedia.org/wiki/O%C5%9Bwiecenie_(epoka)\" target=\"_blank\" rel=\"noopener noreferrer\">oświeceniu</a> i <a href=\"https://pl.wikipedia.org/wiki/Romantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">romantyzmie niemieckim</a>. Jego metaforę jaskini eksploatuje późniejsza filozofia i kultura aż po XX-wieczną <a href=\"https://pl.wikipedia.org/wiki/Teoria_krytyczna\" target=\"_blank\" rel=\"noopener noreferrer\">teorię krytyczną</a>, <a href=\"https://pl.wikipedia.org/wiki/Alienacja\" target=\"_blank\" rel=\"noopener noreferrer\">teorię alienacji</a> człowieka, <a href=\"https://pl.wikipedia.org/wiki/Egzystencjalizm\" target=\"_blank\" rel=\"noopener noreferrer\">egzystencjalny</a> dyskurs autentyczności, <a href=\"https://pl.wikipedia.org/wiki/Psychoanaliza\" target=\"_blank\" rel=\"noopener noreferrer\">psychoanalizę</a>, czy nawet popkulturę, czego przykładem są filmy <i><a href=\"https://pl.wikipedia.org/wiki/Matrix\" target=\"_blank\" rel=\"noopener noreferrer\">Matrix</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Oni_%C5%BCyj%C4%85\" target=\"_blank\" rel=\"noopener noreferrer\">Oni żyją</a></i> oraz twórczość <a href=\"https://pl.wikipedia.org/wiki/Bill_Hicks\" target=\"_blank\" rel=\"noopener noreferrer\">Billa Hicksa</a>. Jego dialogowi filozoficznemu <i><a href=\"https://pl.wikipedia.org/wiki/Kratylos_(dialog)\" target=\"_blank\" rel=\"noopener noreferrer\">Kratylos</a></i> przypisuje się znaczenie językoznawcze, gdyż porusza on problematykę związku między słowami a <a href=\"https://pl.wikipedia.org/wiki/Element_znaczony\" target=\"_blank\" rel=\"noopener noreferrer\">treściami oznaczanymi</a>. Platon bywa uważany za założyciela <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a>.", "Pedro": "<p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pierre": "<p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Petru": "<p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Paolo": "<p>Książę Paolo Troubetzkoy (pawel Petrović Troubetzkoj, włoski Paolo Troubetzkoi; 15 lutego 1866, Verbania, Włochy - 12 lutego 1938, tamże) - włoski i rosyjski rzeźbiarz, zwolennik impresjonizmu, jeden z najbardziej znanych wojaterów ⁇ pragnianej epoki ⁇; mistrz monumentał i portretowej plastiki, twórca słynnego konnego pomnika cesarza Aleksandra III w Sankt-Peterburgu.</p>", "Prakash": "<p>Prakash jest powszechną męską nazwą i nazwą w Azji Południowej, szeroko stosowaną w Nepalu, Indiach i Sri Lance. Słowo prakash pochodzi z sanskrytu prakāśa, co oznacza \"światło jasne\" lub \"świetło słońca\" lub \"swiatło księżyca\" lub \"Światło\", z połączenia pra oznacza \"za\" i kāśa oznacza \"świetlanie\".</p>", "Pietro": "<p>Piotr (Pietro) - katolicki czołowy działacz IX wieku. Stał się presbyter cardinalis prawdopodobnie w konsistorii 875 roku.</p>", "Pylyp": "<p>Pylyp (ukrainański: Пилип) jest ukraińskim męskim imieniem, krewny Filipa. Do wybitnych osób z nazwiskiem należą: Pylyp Budkivskyi (ur. 1992), ukraiński piłkarz Pylyp Harmash (ur. 1989), ukraiński piłkarzek siatkówki Pylyp Kozytskiy (1893-1960), ukraińskiego kompozytora i muzykalem Pylyp Morachevskyi (1806-1879), ukraińca i tłumacza Pylyp Orlyk (1672-1742), ukraienskiego hetmana</p>", "Paskal": "Nazwa <i>paskal</i> pochodzi od nazwiska francuskiego fizyka <a href=\"https://pl.wikipedia.org/wiki/Blaise_Pascal\" target=\"_blank\" rel=\"noopener noreferrer\">Blaise’a Pascala</a>.", "Polikarp": "<b>Polikarp</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>polykarpos</i> oznaczającego „płodny”.", "Prince": "<p>Prince Rogers Nelson (ang. Prince Rogers Nelson; 7 czerwca 1958[...], Minneapolis, Minnesota - 21 kwietnia 2016[...], Shanhaassen) - amerykański muzyk, piosenkarz, gitarzysta-wirtuoz, multiinstrumentalist, autor piosenek, kompozytor, producent, aktor, reżyser.</p>", "Petrus": "<p>Żółty kamienny zęb (lat. Petrus rupestris) - rodzaj morskiej ryby promieniowania rodziny sparowych, jedyny przedstawiciel rodu kamiennych zębów (Petrus).</p>", "Per": "<p>Per: per - łaciński pretekst, odpowiadający słowom ⁇ ceрез ⁇ , ⁇ skvoзь ⁇ , ??po ⁇ lub ⁇ wzdłuż ⁇; część oznaczeń naukowych (np. per capita) i krytycznych fraz (np., per aspera ad astra). PeR - lotyjski pop-grupowy, założony w 2007 roku.</p>", "Przybysław": "<b>Przybysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Przyby-</i> („przybyć, przybywać”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który przynosi sławę”. W tekstach w języku polskim wystąpiło w 1194 roku, a w formie zdrobniałej <b>Przybysz</b> w 1204 r.", "Parviz": "<p>Parvēz, Pērvaz, Parviz lub Parvīs (perskiego: پرویز, پرویز w Nastaliq, oznacza \"szczęśliwy, zwycięski\"; średnioperskiego: plwyc Parvēz , również ʾplwyc Abarvēz/Aparvēz), to perskie imię męskie, w większości popularne w Iranie, Azji Środkowej, Azji Południowej i wśród Azerbejdżanów. Jest to również bardzo powszechne nazwisko.</p>", "Paulin": "<b>Paulin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od imienia <i>Paulus</i> (<a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>) i oznaczające \"<i>należący do Paulusa, pochodzący od Paulusa</i>\". Imię to jest znane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1230\" target=\"_blank\" rel=\"noopener noreferrer\">1230</a> roku. Wśród świętych o tym imieniu – m.in. <a href=\"https://pl.wikipedia.org/wiki/Paulin_z_Noli\" target=\"_blank\" rel=\"noopener noreferrer\">św. Paulin z Noli</a>, biskup.", "Pius": "<b>Pius</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „pobożny”, „cnotliwy”. Jako przydomek imię to po raz pierwszy pojawiło się u <a href=\"https://pl.wikipedia.org/wiki/Cesarze_rzymscy\" target=\"_blank\" rel=\"noopener noreferrer\">cesarza rzymskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Antoninus_Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina Piusa</a> (pan. 138–161). Imię to przyjęło dwunastu <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a>.", "Parys": "Na kilka dni przed porodem jego matka miała sen, że „wydała na świat żagiew płonącą, od której spłonęło całe miasto”. Wróżbici przepowiedzieli, że dziecko będzie przyczyną upadku <a href=\"https://pl.wikipedia.org/wiki/Troja\" target=\"_blank\" rel=\"noopener noreferrer\">Troi</a>. Zostało więc oddane pasterzowi Agelaosowi, aby ten porzucił chłopca w górach. Agelaos jednak nadał chłopcu imię Parys i wychował razem ze swoimi dziećmi. Gdy Parys dorósł, Priam i Hekabe, nie wiedząc nic o królewskim pochodzeniu młodzieńca, przyjęli go do swego domu i ożenili z <a href=\"https://pl.wikipedia.org/wiki/Ojnone\" target=\"_blank\" rel=\"noopener noreferrer\">Ojnone</a>. Rozpoznał go dopiero jego brat, <a href=\"https://pl.wikipedia.org/wiki/Deifobos\" target=\"_blank\" rel=\"noopener noreferrer\">Deifobos</a>.", "Pankracy": "<b>Pankracy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „wszechmocny”, a powstało przez złożenie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;παν (<i>pan</i> – „wszystko, wszech-”) i κρατος (<i>kratos</i> – „moc, siła”). W chrześcijaństwie prawosławnym imię to używane jest jako przydomek <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>; posiada ono również swojego świętego patrona. <b>Pankracy</b> <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/3_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">3 kwietnia</a> i <a href=\"https://pl.wikipedia.org/wiki/12_maja\" target=\"_blank\" rel=\"noopener noreferrer\">12 maja</a>.", "Pankaj": "<p>Pankaj jest powszechną nazwą w Indiach i Nepalu. Jego korzenie pochodzą z słowa sanskrytycznego pankaja, które odnosi się do kwiatu lotosu.</p>", "Petre": "<p>Petre to nazwisko i nazwisko pochodzące od Piotra. Do znanych osób z tą nazwą należą:</p>", "Pilip": "<p>Pilip to męskie imię, spokrewnione z Philipem. Może odnosić się do: Pilip Ballach Ó Duibhgeannáin (fl.</p>", "Plamen": "<b>Płamen</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a>&#160;Пламен) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia bułgarskiego, którego znaczenie odnosi się do <a href=\"https://pl.wikipedia.org/wiki/P%C5%82omie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">płomenia</a>.", "Prashant": "<p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Pramod": "<p>Pramod oznacza radość lub szczęście w sanskrcie i jest jedną z nazw hinduskiego boga Ganesha. Osoby z nazwiskiem \"Pramod\": A.</p>", "Patrice": "<p>Patrice (pełna: Patrice Bart-Williams) - afro-niemiecki wykonawca w stylu reggi.</p>", "Przemek": "<p>Przemysław (polska: [pʂɛˈm ⁇ .swaf]) to polskie imię męskie. Pochodzi od polskiej nazwy Przemysł, krewnego czeskiego Přemysl, a wspólnego słowiańskiego elementu sława oznacza \"sława, sławę\".</p>", "Prokop": "<b>Prokop</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <i>προκοπή</i> – <i>prokope</i>, „postęp, rozwój”, w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a> <a href=\"https://pl.wikipedia.org/wiki/Gens\" target=\"_blank\" rel=\"noopener noreferrer\">gens</a>, z którego wywodzili się m.in. <a href=\"https://pl.wikipedia.org/wiki/Prokopiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Prokopiusz</a> – uzurpator cesarskiego tronu oraz cesarz zachodniorzymski <a href=\"https://pl.wikipedia.org/wiki/Antemiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Prokopiusz Antemiusz</a>. Używane też w <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">kościołach chrześcijańskich</a>: wśród patronów <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Prokop\" target=\"_blank\" rel=\"noopener noreferrer\">święty Prokop</a> (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>) oraz czeski święty <a href=\"https://pl.wikipedia.org/wiki/Prokop_z_Sazawy\" target=\"_blank\" rel=\"noopener noreferrer\">Prokop z Sazawy</a> (<a href=\"https://pl.wikipedia.org/wiki/X_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">X</a>/<a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI wiek</a>).", "Prosper": "<b>Prosper</b> (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>prosperus</i> – „pomyślny, szczęśliwy”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia łacińskiego, znane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a>, po raz pierwszy zanotowane w <a href=\"https://pl.wikipedia.org/wiki/1388\" target=\"_blank\" rel=\"noopener noreferrer\">1388</a> roku.", "Prabin": "<p>Prabin to męskie imię. Wśród znanych osób z nazwiskiem są: Prabin Kumar Chaudhuri (1918-1975), indyjski polityk Prabin Hazarika (fl.</p>", "Paschalis": "<b>Paschalis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, następnie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Wielkanoc\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkanoc</a>. Wywodzi się od aramejskiego, słowa „<a href=\"https://pl.wikipedia.org/wiki/Wielkanoc\" target=\"_blank\" rel=\"noopener noreferrer\">pascha</a>” lub też <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Pesach\" target=\"_blank\" rel=\"noopener noreferrer\">Pesach</a></i> oznaczającego żydowskie święto wyjścia, upamiętniające opuszczenie <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egiptu</a> i początek drogi do <a href=\"https://pl.wikipedia.org/wiki/Ziemia_Obiecana_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi Obiecanej</a>, także przypadającego w znaną już wcześniej Paschę. <b>Paschalis</b> jest polskim odpowiednikiem francuskiego imienia <i>Pascal</i>.", "Petteri": "<p>Petteri to fińskie imię męskie, oznaczające Petera. Do osób z tym nazwiskiem należą: Petteri Forsell (ur. 1990), fiński piłkarz Piłkarz Petteri Iivonen (ur. 1987), fiński skrzypiec Petteri Kaijasilta (ur. 1974), fiński Piłkarze Piłkarza Piłkarzy Kupiainen (ur. 1960), fińskiPiłkarz Płkarz Koponen (ur., 1988), fiński profesjonalny koszykarz Piękarz Lampinen (ur., 1975), fiński gracz bandy Petteri Lax (ur. 1985), fiński długo...</p>", "Pranav": "<p>Pranav (sanskrit: प्रणव, romanized: Praṇava) to indyjskie imię męskie oznaczające Om, święty dźwięk i symbol. Według hinduizmu pranawa jest zdaniem siłą Brahmę, Wisnu i Shiwy łączonej.</p>", "Pratik": "<p>Pratik lub Prateik to indyjska męska nazwa, która może odnosić się do Prateika Babbar (ur. 1986), indyjskiego aktora Pratik Chaudhari (ur. 1989), indyskiego piłkarza Pratik Desai (ur. 1989, indyjski kryker Pratik Gandhi, indyjski aktor teatralny i filmowy Prateik Jain (ur. 1989.), indyjski model i aktor Pratik Prakashbapu Patil (ur. 1973), indyjscy polityk Pratik A. Shah, amerykański prawnik Pratik Salunke (ur. 1991), indyjska krykerka Pratik...</p>", "Preston": "<p>Preston lub Prestons mogą odnosić się do:</p>", "Prokhor": "<p>Prokhor (rosyjski: Прохор) to rosyjska nazwa pochodząca z greckiej nazwy Prochoros (Προχορος), która była nazwiskiem świętego. Jego drobne formy obejmują Pronya, Pronka, Prokhorka, Prokha, Prosha, Proshka i Proshenka.</p>", "Protazy": "<b>Protazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Według części badaczy posiada ono grecką postać, <i>Prōtās</i>, która stanowi pierwotne zdrobnienie imion dwuczłonowych typu <i>Prōtoarchos</i>, <i>Protagoras</i>, <i>Prōtogenēs</i> itp.&#8201;&#8201; – pierwszy człon, <i>prōtos</i>, oznacza „pierwszy, przedni”&#8201;; inni natomiast wywodzą to imię od gr. imienia Προτασιος (<i>Prōtasios</i>), pochodzącego od προτασσω – „umieszczam, stawiam na czele”&#8201;. W Polsce notowane od średniowiecza, w formach <i>Prothasius</i> (od <a href=\"https://pl.wikipedia.org/wiki/1212\" target=\"_blank\" rel=\"noopener noreferrer\">1212</a> r.), Protazy (od <a href=\"https://pl.wikipedia.org/wiki/1438\" target=\"_blank\" rel=\"noopener noreferrer\">1438</a> r.), Protas(z) (wschodniosł., od <a href=\"https://pl.wikipedia.org/wiki/1471\" target=\"_blank\" rel=\"noopener noreferrer\">1471</a> r.)&#8201;.", "Przemyslaw": "<p>Przemysław (polska: [pʂɛˈm ⁇ .swaf]) to polskie imię męskie. Pochodzi od polskiej nazwy Przemysł, krewnego czeskiego Přemysl, a wspólnego słowiańskiego elementu sława oznacza \"sława, sławę\".</p>", "Predrag": "<p>Predrag (Serbski cyrylski: Предраг) to słowiańskie imię męskie, głównie nosione przez etnicznych Słowian, pochodzące od pre- (\"bardzo, wiele\") i -drag (\"kochanie, ukochany\"), oba wspólne w słowiańskich dithematycznych nazw. To znaczy \"bardzo umiłowany\".</p>", "Peleg": "Według Rdz 10,25 Peleg otrzymał swoje imię „gdyż za jego czasów ludzkość się podzieliła” lub „gdyż za jego dni ziemia została rodzielona”. Bibliści wiążą ten fragment z opowiadaniem o <a href=\"https://pl.wikipedia.org/wiki/Wie%C5%BCa_Babel\" target=\"_blank\" rel=\"noopener noreferrer\">Wieży Babel</a> i rozproszeniu się ludzi po Ziemi. Etymologia imienia Pelega wywodzona jest z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskiego</a> <i>palgu</i> „kanał” lub <i>puluggu</i> „okręg”, biblijna wzmianka mogłaby więc odnosić się do <i>podziału</i> ziemi kanałami nawadniającymi lub podziału kraju na okręgi administracyjne. Część <a href=\"https://pl.wikipedia.org/wiki/Kreacjonizm_m%C5%82odej_Ziemi\" target=\"_blank\" rel=\"noopener noreferrer\">kreacjonistów młodej Ziemi</a> uważa, że to zdanie odnosi się do podziału <a href=\"https://pl.wikipedia.org/wiki/Pangea\" target=\"_blank\" rel=\"noopener noreferrer\">Pangei</a>.", "Prot": "<b>Prot</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało poprzez użycie w charakterze imienia greckiego liczebnika <i>prōtos</i>, „pierwszy” lub skrócenie takich dwuczłonowych imion greckich, jak Protagoras, Protarchos, Protonikos, Protogenes. Znaczeniowo odpowiada mu łacińskie imię <a href=\"https://pl.wikipedia.org/wiki/Prymus\" target=\"_blank\" rel=\"noopener noreferrer\">Primus</a>.", "Pawlo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pavlo</b>.</p><p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Petroniusz": "<b>Petroniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> rodowego Petroniuszy (<i>gens Petronia</i>), przy czym nazwa rodu <i>Petronia</i> jest związana prawdopodobnie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskim</a> <i>petruni</i> o nieustalonym znaczeniu. Petroniusz jest nadawany w Polsce co najmniej od pierwszej poł. <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>. Istnieje trzech świętych katolickich o tym imieniu.", "Parker": "<p>Parker (ang. Parker) - angielskie nazwisko, toponim, nazwa firm itp.</p>", "Paulus": "<p>Paweł (lat. Paulus; zmarł w 469 lub 470, Angie) - zachodni rzymski wojskowiec, który w latach 460-470 walczył z вестogotami i saksami.</p>", "Phong": "<p>Phong może oznaczać: Od starożytnego oznacza wiatr; powietrze (klasyczny element) Rodzaj choroby zapalonej; Rodzaj roślin z rodu Phong; Zbyt skrótowe nazwisko rodu, stopień, nazwisko... Pjong dynastii wschodniej Azji; Pong dynastii Chu, China Pong dynasty, China Pyong dynasty z Chin Zhu, Jiangsu, China Wszystkie strony z tytułem \"Phong\" zawierają \"Pong\"</p>", "Poul": "<p>Poul to duńskie imię męskie. To duński krewny nazwiska Paul.</p>", "Pekka": "<p>Pekka to finowska imię męskie. Była najbardziej popularna w połowie XX wieku.</p>", "Purna": "<p>Purna jest miastem i miejscem miejscowości w Parbhani w stanie Maharashtra, India.</p>", "Phoenix": "<p>Phoenix (w transliteracji z angielskiego - również Phoenix; z łac. Phoenix): Phoenix - mityczna ptaka, która posiada zdolność spalić się i następnie odrodzyć się.</p>", "Paris": "<p>Paris: Paris - nazwę francuskiej stolicy Paryża w łacińskim. Paris - album koncertowy brytyjskiej grupy The Cure.</p>", "Petrov": "<p>Petrow, Wszewolód Aleksejewicz (21 lutego 1896 - 1955) - sowiecki paleobotanin, jeden z pionierów sowieckiej metody sporu-polczu, kandydat na naukę biologiczne, депутат Petrogradskiego Rządowego Rady Leningradu w latach 1928 - 1931.</p>", "Parvin": "<p>Parveen (persk: پروین) to perskiej kurdyjskiej nazwy, która oznacza Plejady. Jest powszechnie stosowany w Iranie, Afganistanie, Tadżykistanie, Pakistanie i Indiach.</p>", "Pau": "<p>Karles Paw-i-Espanjol (kat. Carles Pau i Espanyol, hiszpański.</p>", "Precious": "<p>⁇ Precious ⁇ - piosenka brytyjskiej grupy Depeche Mode, pierwszy single z ich jedenastego albumu studiowego Playing the Angel, 41. w dyskografii grupy. Wydał się 3 października 2005 roku w Wielkiej Brytanii i 11 paździennika w USA.</p>", "Polat": "<p>Polat (tur. Polat) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Perez": "<p>Pérez może oznaczać: Nazwisko hiszpańskiego (hisp. Pérez) lub portugalskiego (port.</p>", "Prashanth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Prashant</b>.</p><p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Patrycy": "<b>Patrycy</b> jest to oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Patryk\" target=\"_blank\" rel=\"noopener noreferrer\">Patryk</a> i <a href=\"https://pl.wikipedia.org/wiki/Patrycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycjusz</a>.", "Ping": "<p>Ping - użyteczność do sprawdzenia integralności i jakości połączeń w sieciach na podstawie TCP/IP, a także nazwy użytkowej zapytania. Utilito wysyła ICMP Echo-Request do wskazanego węzła i rejestruje otrzymane ICMP Echo -Reply.</p>", "Phi": "<b>Phi</b> (<b>fi</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;φῖ, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>φι</b>, pisana <b>Φφ</b> lub <b>ϕ</b>) – dwudziesta pierwsza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/500_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">500</a>.", "Paz": "<b>Paz</b> – żeńskie imię hiszpańskie oznaczające <i>Pokój</i>.", "Percy": "<p>Percy może odnosić się do: Percy, Isère, gmina w prowincji Isère w regionie Rhône-Alpes w południowo-wschodniej Francji. Percy, Manche, gmina w prowincji Manche, w francuskim obszarze administracyjnym Normandia.</p>", "Priyantha": "<p>Priyantha może odnosić się do Ashoka Priyantha, polityka Sri Lankan Janaka Priyantha Bandara, polityka Śri Lanka Priyantha Jayawardena, sędzia Priyantha Perera - Komendant Morza Morza Morskiego Sri Lanki od 2022 do 2024 Nalin Priyantha , atleta Sri Lanka</p>", "Petrit": "<p>Petrit (lit. 'Falcon') to albaniańska męska nazwisko i może odnosić się do: Petrit Ago, dyrektor generalny celnej Albanii Petrit Bushati (1948-2014), ambasador albania Petrit Çeku (urodzony 1985), kosowskiego gitarzystę klasycznego Petrit Dibra (urodzona 1953), albanianki piłkarz Petrit Dume (1920-1975), albaniański generał i polityk Petrit Fejzula (urodzono 1951), jugosławski piłkarzek rękawy Petrit Frrokaj (urodzone 1985), szwajcarz piłkarze Petrit Halilaj ...</p>", "Perry": "<p>Perry (ang. Perry) - angielskojęzyczna nazwisko, imię i toponim.</p>", "Perman": "<p>Perman (jap. パーマン Pa:man) - japońska manga, autorem której jest duet Fujico Fujio.</p>", "Parvez": "<p>Parvēz, Pērvaz, Parviz lub Parvīs (perskiego: پرویز, پرویز w Nastaliq, oznacza \"szczęśliwy, zwycięski\"; średnioperskiego: plwyc Parvēz , również ʾplwyc Abarvēz/Aparvēz), to perskie imię męskie, w większości popularne w Iranie, Azji Środkowej, Azji Południowej i wśród Azerbejdżanów. Jest to również bardzo powszechne nazwisko.</p>", "Paras": "<p>Paras - jargonowe nazwisko Pułku Parachutnego, elitarnego utworzenia wojsk powietrznych i desantów Wielkiej Brytanii.</p>", "Panteleimon": "<p>Panteleimon lub Panteley mogą odnosić się do:</p>", "Piet": "<p>Piet - ezoteryczny język programowania opracowany przez Davida Morgan-Mara. Piet używa różnorodnych obrazów jako programów.</p>", "Piast": "<p>Piast - legendarny przodek dynastii Piastów.</p>", "Parveen": "<p>Parveen (persk: پروین) to perskiej kurdyjskiej nazwy, która oznacza Plejady. Jest powszechnie stosowany w Iranie, Afganistanie, Tadżykistanie, Pakistanie i Indiach.</p>", "Phan": "<p>Phan może być: Họ Phan, rodzina mieszkańców Wietnamu, Chin i Korei Północnej Huyện Phan (Tajówki: อําเภอพาน), prowincji Chiang Rai, Tajlandii Xan Phan, prowincji Yang Minh Châu, prowincja Tsinh Ninh, Wietnam rzeka Phan, nazwy dwóch rzek w Pyongyang i Vịnhúc, Wietnamy</p>", "Phariz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fariz</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fariza</b>.</p><p>Fariza jest miastem w prowincji Zamora, Kastilia i Leon, Hiszpania. Według przeprowadzonego w 2004 roku popytu (INE) mieście miało 689 mieszkańców.</p>", "Piotrek": "<p>Peter to powszechne męskie imię. Pochodzi bezpośrednio z greckiego Πέτρος, Petros (wynaleziona, męska forma greckiego petra, słowo dla \" skały \"lub \"kamień\"), które samo w sobie było tłumaczeniem aramejskiego Kefa (\"kamień, skała\"), nowa nazwa, którą Jezus dał apostołowi Simon bar Jona.</p>", "Pantaleon": "<b>Pantaleon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πανταλέων). Wywodzi się ze złożenia słów παντα oznaczającego \"wszystko\" i λέων oznaczającego \"lew\". Według innej wersji <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Παντελεήμων (Pantelejmon) - „najmiłościwszy”.", "Peer": "<p>Jednoręczna, zdecentralizowana lub pieringowa (ang. peer-to-peer, P2P - równa równej) sieć - sieć komputerowa owrętowa, oparta na równości uczestników.</p>", "Pranay": "<p>Pranay jest hinduskim imieniem męskim, co oznacza \"miłość\" lub \"troskę\". Wśród znanych osób z tym nazwiskiem są: Pranay Chulet, indyjski przedsiębiorca, założyciel Quikr Pranay Gupte, amerykański-indyjski dziennikarz, autor i założyciel gazety Pranaya SJB Rana, nepalijski dziennikarka, autor i redaktor gazety Pranay Sahay, indyjskie policjant Pranay Sharma, indyjscy kryketacz Dasyam Pranay Bhasker, indyjska polityk Pranayraj Vangari,...</p>", "Phương": "<p>Położenie może oznaczać jedno z następujących: kierunek: Stojące, równoległe lub wschodnie, zachodnie, południowe, północne. Wykład: jednostka wagi masy używana podczas grzewania ryżu...</p>", "Parsa": "<p>Ahmad Parsa (ang. Ahmad Parsa, czyli angielski.</p>", "Percival": "<p>John Percival (ang. John Percival 1863 - 1949) - angielski botanik, wybitny naukowiec, założyciel botaniki rolnej jako dyscypliny naukowej, systematyka, tritikolog, genetyka, selekcjoner, agronom, historyk botaniki i nauczyciel.</p>", "Pontus": "W odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Okeanos\" target=\"_blank\" rel=\"noopener noreferrer\">Okeanosa</a> – boga morza zewnętrznego, czyli wód opływających Ziemię, był bogiem niedostępnego ludziom morza wewnętrznego w trzewiach Ziemi. Z upływem czasu jego imię stało się ogólnym określeniem akwenu morskiego – np. <i>Axeinos Pontos</i>, <i><a href=\"https://pl.wikipedia.org/wiki/Morze_Czarne\" target=\"_blank\" rel=\"noopener noreferrer\">Euxeinos Pontos</a></i>. Pochodną jest także nazwa nadczarnomorskiej krainy <a href=\"https://pl.wikipedia.org/wiki/Pont\" target=\"_blank\" rel=\"noopener noreferrer\">Pont</a>.", "Phil": "<p>- To mniejsze imię od Filipa, a także jego nazwa. Phil to lasówka z miasta Panksatoni, która przepowiada pogodę.</p>", "Pedro Luis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Promise": "<p>Promise (ang. obietnica, obiecać) może oznaczać: (The) Promise: ⁇ The Promise ⁇ (2008) - single brytyjskiej grupy pop-grupowej Girls Aloud; Promise (1985) - drugi album angielskiej grupy soul-grupowego Sade; The Promise (1995) - album angielskiego muzyka jazzu Johna McLafflina; The Promase (2010) - album zbiorowy Bruce Springstina; The Promese (2008) - album grupy Il Divo; The Promite (2004) - piąty album studiowy grupy bluesa-rock Con Vaya Dios;...</p>", "Panayiotis": "<p>Panagiotis lub Panayiotis jest powszechną imieniem dla mężczyzn. Pochodzi z greckiego epitetu Panagia lub Panayia (\"Wszyscy Święci\") dla Maryi.</p>", "Parman": "<p>Perman (パーマン, Pāman) to japoński manga napisany przez Fujiko Fujio. Nazwa \"Perman\" pochodzi od \"Superman\" z wyjątkiem \"Su\".</p>", "Parminder": "<p>Parminder Kaur Nagra (ang. Parminder Kaur Nagra; rodzaj.</p>", "Parfait": "<p>Parfait (, also UK: , francuski: [paʁfɛ]; oznacza \"doskonały\") jest jednym z dwóch rodzajów deserów. W Francji, gdzie pochodzi, parfait jest robiony przez gotowanie śmietanki, jaj, cukru i syrosu, aby stworzyć mieszankę delikatnej jak mleko jaj.</p>", "Pedro Miguel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pierre-Marie": "<p>Pierre-Marie to francuskie męskie imię i może odnosić się do: Pierre-Maré Carré (ur. 1947), francuskiego prelata Kościoła katolickiego Pierre-Mary Coty (1927-2020), rzymskokatolicznego biskupa Pierre-Marye Delfieux (1934-2013), francuskiego kapłana rzymskokorodowskiego Pierre-Marée Deloof (ur. 1964), belgijskiego remnika Pierre-MarIE Dioudonnat (ur. 1945), francuskiego wydawcy, historyka i politologa Pierre-Marire Dong (1945-2006), gabonskiego filmu...</p>", "Przemił": "<b>Przemił</b>, <b>Przemieł</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Prze-</i> (\"przez\" i wiele innych znaczeń) i <i>-mił</i>, <i>-mieł</i> (\"miły\"). Być może oznaczało \"najmilszy\".", "Patryck": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patrick</b>.</p><p>Patrick (ang. Patrick) - męskie imię pochodzące od łacińskiego.</p>", "Palermo": "<p>Palermo (Sicilian: Palermu, Latin; Panormus, Grecki: Πάνορμος, Panormos) to historyczne miasto w południowej Włoszech, stolica autonomii Sycylii i prowincji Palermo. Miasto jest znane z historycznej, kulturalnej, architektonicznej, tradycyjnej kuchni, które wiążą się z miastem od ponad 2700 lat.</p>", "Perun": "<b>Perun</b> (właśc. <b>Pierun</b>; także <b>Piorun</b>, <b>Pieron</b>) – <a href=\"https://pl.wikipedia.org/wiki/Religia_S%C5%82owian\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie bóstwo</a> gromowładne oraz jedno z czołowych w <a href=\"https://pl.wikipedia.org/wiki/Panteon\" target=\"_blank\" rel=\"noopener noreferrer\">panteonie</a> słowiańskim. „Perun” to zaproponowane przez niektórych badaczy tematu imię wynikłe z nazwy gromu perunъ powiązanej z <a href=\"https://pl.wikipedia.org/wiki/Leksem\" target=\"_blank\" rel=\"noopener noreferrer\">leksemem</a> pьrati, 'bić, uderzać' jako oznaczające jedno z naczelnych bóstw słowiańskich. Uosobienie gromowładcy, boga grzmotów i piorunów. Według zamysłu badaczy ma ono porządkować poszczególne ślady wierzeniowe, jakie pozostawił po sobie kult słowiańskich, plemiennych bóstw gromowładnych. Są to między innymi: w tradycji staropolskiej imię Piorun lub Grom, w polskich porzekadłach ludowych także Pierun, w tradycji staroruskiej Перун (czyt. Pierun). W kulturze masowej imię Perun używane jest najczęściej w odniesieniu do naczelnego bóstwa gromowładnego <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_wschodni\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian wschodnich</a>.", "Pan": "<p>Pan lub PAN może oznaczać: technika obliczeniowa: Sieć osobowa (ang. Personal Area Network) - sieć przekazywania danych łącząca osobiste urządzenia elektroniczne jednego użytkownika (telefony, kieszeni personalne komputery, smartfony, notebooky, bezprzewodowe armatury itp.</p>", "Paxton": "<p>Joseph Paxton (ang. Joseph Paxson, 3 sierpnia 1803, Milton-Brien, Bedfordshire - 8 czerwca 1865, Sydney, London) - angielski architekt, inżynier, ogrodnik i botanik.</p>", "Pastor": "<p>Różowy skworek (lat. Pastor roseus) - ptak z rodziny skworek, bliski krewny zwykłego skworka.</p>", "Phurba": "<b>Phurba</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tyb</a>: སྤྲུལ་པ <a href=\"https://pl.wikipedia.org/wiki/Transliteracja_Wyliego\" target=\"_blank\" rel=\"noopener noreferrer\">Wylie</a>: sprul-pa) – trójstronny <a href=\"https://pl.wikipedia.org/wiki/Sztylet\" target=\"_blank\" rel=\"noopener noreferrer\">sztylet</a> rytualny używany w tybetańskiej tradycji <a href=\"https://pl.wikipedia.org/wiki/B%C3%B6n\" target=\"_blank\" rel=\"noopener noreferrer\">bön</a>, <a href=\"https://pl.wikipedia.org/wiki/Buddyzm_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie tybetańskim</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">nepalskim</a> <a href=\"https://pl.wikipedia.org/wiki/Szamanizm\" target=\"_blank\" rel=\"noopener noreferrer\">szamanizmie</a> zwanym <a href=\"https://pl.wikipedia.org/wiki/D%C5%BAhankri\" target=\"_blank\" rel=\"noopener noreferrer\">dźhankri</a>. Sanskryckim odpowiednikiem jest <i>kilaja</i>.", "Peyman": "<p>Peyman (pay-MAHN), również romanizowany jako Peymân (perskie: پیمان [phejˈmɒːn]), Paymān (Dari: پیمان [phajˈmɑːn]) lub Paymon (tajdżki: Паймон [phajʹmɔːn]). W języku perskim nazwa ta przetłumaczona jest jako 'formalne porozumienie' lub 'przysięga', a używana jest również do odniesienia się do przymierza biblijnego pomiędzy Bogiem a Żydami.</p>", "Pride": "<p>Pride Fighting Championships (jap. Pride, skarbie.</p>", "Phuad": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fuad</b>.</p><p>Fuad (arabski: َفؤَاد fū\"ād, fou\"ād) (zwany również Fouad, Foud, Fuaad lub Foad) jest męskim arabskim nazwiskiem, co oznacza \"serce\" - bijące się serce, pojęcie \"umysłu i ducha\". Jego pierwotnym słowem jest arabski czasownik fa'ada (arabski: َفَأَد), co oznacza \"palenie lub płomień\", a lahmun fa'eed, co oznacza \"masło pieczone na ognie\".</p>", "Pere": "<p>Pere jest miastem w hęgierskim prowincji Borsod-Abaúj-Zemplén. Miasto ma powierzchnię 9,56 km2, liczba ludności w 2010 roku wynosi 356 mieszkańców, a jego gęstość 37 mieszkańców/km2.</p>", "Philemon": "<p>Philemon jest rodzinną ptakiem z rodziny Meliphagidae.</p>", "Pramod Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pramod</b>.</p><p>Pramod oznacza radość lub szczęście w sanskrcie i jest jedną z nazw hinduskiego boga Ganesha. Osoby z nazwiskiem \"Pramod\": A.</p>", "Pouya": "<p>Kevin Puya (ur. 20 grudnia 1994, Miami, USA) - miamyński repp- wykonawca, bardziej znany jako Pouya.</p>", "Přemysl": "<p>Przemysl (czeski Přemysl; 1209 - 16 października 1239) - margraf Morawii (1228 - 1239) z dynastii Przemysłów, syn króla Czechy Przemysł Ototkar I i Konstancji Węgierskiej.</p>", "Pelayo": "<p>Pelaio (Pelagij; hisz. Pelayo, lat.</p>", "Pantelis": "<p>Pantelis lub Pandelis (grecki Παντελής; nowoczesne: [pa de ˈlis]) jest nazwą pochodzenia greckiego, która jest nazwą:</p>", "Pervez": "<p>Parvēz, Pērvaz, Parviz lub Parvīs (perskiego: پرویز, پرویز w Nastaliq, oznacza \"szczęśliwy, zwycięski\"; średnioperskiego: plwyc Parvēz , również ʾplwyc Abarvēz/Aparvēz), to perskie imię męskie, w większości popularne w Iranie, Azji Środkowej, Azji Południowej i wśród Azerbejdżanów. Jest to również bardzo powszechne nazwisko.</p>", "Pawan Kumar": "<p>Pawan Kumar (ur. 12 maja 1995) jest indyjski piłkarz, który gra w środku dla FC Pune City w Indian Super League.</p>", "Padraig": "<p>Pádraig lub Pádraic (ang. PAW- (d) rig, -rik, irlandzki: [ˈpɣaːd̪ɣɾɣəɟ, -əc]), również Pádhraig lub Pádhraic , to irlandzkie męskie nazwiska pochodzące od łacińskiego Patricius, co oznacza \"z klasy patricjan\", wprowadzone za pośrednictwem imienia św. Patryka. Nazwa jest często angliczowana jako jej językowy odpowiednik angielski Patrick lub fonetycznie, np.</p>", "Pedro Pablo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Petrea": "<p>Petrea (lat. Petrea) - rodzaj dwustronnych roślin kwiatowych, włączony do plemienia Petreeae rodziny Verbenaceae.</p>", "Pentti": "<p>Pentti to fińskie imię i nazwisko męskie, forma Bengt (Szwedzki dla Benedykta). Pentti była bardzo popularną nazwą w latach 1920-1950.</p>", "Pablo Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Przesław": "<b>Przedsław</b>, <b>Przecław</b>, <b>Przecsław</b>, <b>Przesław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Przed-</i> (pierwszy człon posiadał wiele różnych znaczeń, zależnych od znaczenia drugiego członu imienia) i <i>-sław</i> („sława”). Imię notowane w Polsce od 1153 roku. Mogło oznaczać „ten, który stawia sławę ponad inne rzeczy”, „stawiający wyżej sławę”. Możliwe staropolskie zdrobnienia to: Przech, Przechno, Przeczek, Przeczko, Przeczk, Przeczka (masc.), Przeczeń, Przeczno, Przesz, Przeszek, Przeszko.", "Pankaj Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pankaj</b>.</p><p>Pankaj jest powszechną nazwą w Indiach i Nepalu. Jego korzenie pochodzą z słowa sanskrytycznego pankaja, które odnosi się do kwiatu lotosu.</p>", "Prabath": "<p>Prabath to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Pierre-Yves": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Płamen": "<b>Płamen</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a>&#160;Пламен) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia bułgarskiego, którego znaczenie odnosi się do <a href=\"https://pl.wikipedia.org/wiki/P%C5%82omie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">płomenia</a>.", "Philippos": "<p>Philippos to męskie imię, spokrewnione z Philipem. Wśród znanych osób z nazwiskiem: Philippos Constantinos, cypryjski piosenkarz Philippos Syrigos (1948-2013), grecki dziennikarz śledczy i reporter sportowy</p>", "Pierre-Antoine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pharman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Farman</b>.</p><p>Henri Farman (francuski: Henri Farman)  Henri Farman, angielski.</p>", "Pedro Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pedro Manuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pathum": "<p>Pathum to imię. Znani ludzie z nazwiskiem to: Pathum Dilshan (ur. 1991), kryketar Sri Lankan Pathum Madusanka (ur. 1996), kryketer Sri Lankan Patum Nissanka (ur. 1998), kryketarka Sri Lanka</p>", "Paig": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Paige</b>.</p><b>Paige</b> – angielskie imię, odmiana imienia \"Page\", spotykana jest także wersja \"Payge\". Współcześnie imię zazwyczaj jest nadawane kobietom, choć tradycyjnie uważane jest za \"unisex\".", "Perhat": "<p>Perhat (Uighur: پەرھات) jest męskim imieniem uighurskim. Znani ludzie z imieniem to: Perhat Khaliq (ur. 1982), chiński uygurski kompozytor pop-rock i muzyk Perhat Tursun (ur. 1969), uygurski pisarz i poeta</p>", "Prasant": "<p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Prashanta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Prashant</b>.</p><p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Phi Hùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Phi</b>.</p><b>Phi</b> (<b>fi</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;φῖ, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>φι</b>, pisana <b>Φφ</b> lub <b>ϕ</b>) – dwudziesta pierwsza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/500_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">500</a>.", "Puiu": "<p>Puiu to zarówno rumuńskie imię i nazwisko męskie. Wśród znanych osób z nazwiskiem są: Cristi Puiu (ur. 1967), rumuński reżyser filmowy i scenarzysta Visarion Puiu (1879-1964), rumuinski biskup prawosławny Puiu Dumitrescu, sekretarz prywatny króla Karola II Puiu Hașotti (ur. 1953), rumuinski polityk Puiu Manu (ur. 1928), rumuńczy graficzny projektant i twórca komiksów</p>", "Pedro Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pierrick": "<p>Pierrick to imię z Bretanii, diminutiwne Pierre. Pierrick Bourgeat (ur. 1976), francuski narciarz alpiński Pierrick Capelle (ur. 1987), francuski profesjonalny piłkarz Pierrick Cros (ur. 1991), piłkarze Pierrick Cros, ur. 1992), piłkacz Pierrick Fédrigo (ur. 1978), francuski rower Pierrick Gunther (ur. 1989),...</p>", "Płaton": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Platoni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Platon</b>.</p>Wzrost popularności myśli Platona oraz istotne postępy w badaniach nad jego tekstami zbiegały się z ważnymi przełomami w <a href=\"https://pl.wikipedia.org/wiki/Historia_filozofii_(nauka)\" target=\"_blank\" rel=\"noopener noreferrer\">historii filozofii i nauki</a>, szczególnie w okresie <a href=\"https://pl.wikipedia.org/wiki/Renesans\" target=\"_blank\" rel=\"noopener noreferrer\">renesansu</a> we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> oraz w <a href=\"https://pl.wikipedia.org/wiki/O%C5%9Bwiecenie_(epoka)\" target=\"_blank\" rel=\"noopener noreferrer\">oświeceniu</a> i <a href=\"https://pl.wikipedia.org/wiki/Romantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">romantyzmie niemieckim</a>. Jego metaforę jaskini eksploatuje późniejsza filozofia i kultura aż po XX-wieczną <a href=\"https://pl.wikipedia.org/wiki/Teoria_krytyczna\" target=\"_blank\" rel=\"noopener noreferrer\">teorię krytyczną</a>, <a href=\"https://pl.wikipedia.org/wiki/Alienacja\" target=\"_blank\" rel=\"noopener noreferrer\">teorię alienacji</a> człowieka, <a href=\"https://pl.wikipedia.org/wiki/Egzystencjalizm\" target=\"_blank\" rel=\"noopener noreferrer\">egzystencjalny</a> dyskurs autentyczności, <a href=\"https://pl.wikipedia.org/wiki/Psychoanaliza\" target=\"_blank\" rel=\"noopener noreferrer\">psychoanalizę</a>, czy nawet popkulturę, czego przykładem są filmy <i><a href=\"https://pl.wikipedia.org/wiki/Matrix\" target=\"_blank\" rel=\"noopener noreferrer\">Matrix</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Oni_%C5%BCyj%C4%85\" target=\"_blank\" rel=\"noopener noreferrer\">Oni żyją</a></i> oraz twórczość <a href=\"https://pl.wikipedia.org/wiki/Bill_Hicks\" target=\"_blank\" rel=\"noopener noreferrer\">Billa Hicksa</a>. Jego dialogowi filozoficznemu <i><a href=\"https://pl.wikipedia.org/wiki/Kratylos_(dialog)\" target=\"_blank\" rel=\"noopener noreferrer\">Kratylos</a></i> przypisuje się znaczenie językoznawcze, gdyż porusza on problematykę związku między słowami a <a href=\"https://pl.wikipedia.org/wiki/Element_znaczony\" target=\"_blank\" rel=\"noopener noreferrer\">treściami oznaczanymi</a>. Platon bywa uważany za założyciela <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a>.", "Pertti": "<p>Pertti to fińskie imię męskie.</p>", "Petronel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Petronela</b>.</p><b>Petronela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pierwotnie będące formą zdrobniałą imienia <a href=\"https://pl.wikipedia.org/wiki/Petronia\" target=\"_blank\" rel=\"noopener noreferrer\">Petronia</a>.", "Phani": "<p>Phani oznacza węża w sanskrycie. Może odnosić się do: Phani Majumdar, indyjski reżyser Phani Ramachandra, indyjskiego reżysera filmowego i telewizyjnego Phani Sarma, asymskiego aktora i reżyseru Phanis, gatunku żółwia</p>", "Pierre-Henri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pierre Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Prageeth": "<p>Prageeth to imię. Do wybitnych osób z tym nazwiskiem należą: Prageeth Eknaligoda (ur. 1960), szrilankański karykaturysta Prageeth Rambukwella (ur. 1976), kryketer z Sri Lanki.</p>", "Pierre-Louis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pasindu": "<p>Pasindu to imię. Znani ludzie z imieniem Pasindu Bimsara (ur. 1996), kryker z Sri Lanki Pasindu Dilshan (ur. 1996), kryker ze Sri Lanki pasindu Isira, kryker w Sri Lance Pasindu Lakshanka (ur. 1996, kryker Sri LankiPasindu Madushan (ur. 1992), krykera z Sri Lanky Pasindu Sooriyabandara (ur., 1999), kryketer z Sri Lanku Pasindu Ushettige (ur. 1999), krykieter ze Sri Lanky</p>", "Pelagiusz": "<b>Pelagiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego \"marynarz\" (por. <a href=\"https://pl.wikipedia.org/wiki/Pelagial\" target=\"_blank\" rel=\"noopener noreferrer\">pelagial</a>).", "Pafnucy": "<b>Pafnucy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia egipskiego, pierwotnie wywodzące się jednak od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_koptyjski\" target=\"_blank\" rel=\"noopener noreferrer\">koptyjskiego</a> <i>papnute</i>, <i>paphnuti</i> – „człowiek Boży, sługa Boży”. Według innego źródła imię ma pochodzenie <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">greckie</a>.", "Pranab": "<p>Pranab to indyjska nazwa, powszechna wśród Assamów, Bengalczyków, Odia i Nepalisów. Wariant nazwy jest \"Pranav\".</p>", "Peiman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Peyman</b>.</p><p>Peyman (pay-MAHN), również romanizowany jako Peymân (perskie: پیمان [phejˈmɒːn]), Paymān (Dari: پیمان [phajˈmɑːn]) lub Paymon (tajdżki: Паймон [phajʹmɔːn]). W języku perskim nazwa ta przetłumaczona jest jako 'formalne porozumienie' lub 'przysięga', a używana jest również do odniesienia się do przymierza biblijnego pomiędzy Bogiem a Żydami.</p>", "Pham": "<b>Pham</b> (właściwie <b>Dawid Pham Ngoc</b>, ur. <a href=\"https://pl.wikipedia.org/wiki/18_maja\" target=\"_blank\" rel=\"noopener noreferrer\">18 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1994\" target=\"_blank\" rel=\"noopener noreferrer\">1994</a> w <a href=\"https://pl.wikipedia.org/wiki/Nysa\" target=\"_blank\" rel=\"noopener noreferrer\">Nysie</a>) – polski producent muzyczny, remikser i DJ pochodzenia wietnamsko-polskiego.", "Piotr Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Piotr Paweł": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pedro Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Phineas": "<p>Phineas () jest męskim nazwiskiem, anglicizowanym nazwiskiem kapłana Phinehas w Biblii hebrajskiej. Może odnosić się do:</p>", "Pakosław": "<b>Pakosław</b> – starosłowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Pako-</i> („znów, więcej”) i <i>-sław</i> („sława”). Mogło oznaczać „ten, który chce (ma) więcej sławy”. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Ros.</a> odpow. Пакослав.", "Pjotr": "<p>Peter to powszechne męskie imię. Pochodzi bezpośrednio z greckiego Πέτρος, Petros (wynaleziona, męska forma greckiego petra, słowo dla \" skały \"lub \"kamień\"), które samo w sobie było tłumaczeniem aramejskiego Kefa (\"kamień, skała\"), nowa nazwa, którą Jezus dał apostołowi Simon bar Jona.</p>", "Placyd": "<b>Placyd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> pochodzącego od wyrazu pospolitego <i>placidus</i>, oznaczającego „spokojny, dobrotliwy, łagodny”. Notowane w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1691\" target=\"_blank\" rel=\"noopener noreferrer\">1691</a> roku.", "Pedro Henrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pavlo-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pavlo</b>.</p><p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Prochor": "<b>Prochor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od Προχορος – z choreo \"tańczę\"; pro – \"przed\"; imię to oznacza \"ten, co prowadzi taniec; pierwszy tancerz\". <a href=\"https://pl.wikipedia.org/wiki/Prochor_(diakon)\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Prochor</a> był jednym z 7 pierwszych <a href=\"https://pl.wikipedia.org/wiki/Diakon\" target=\"_blank\" rel=\"noopener noreferrer\">diakonów</a>. Polskimi formami tego imienia są: Prochor, Prochorus, Prochort, Profor, Prophiorus, Profortus.", "Pouria": "<p>Pourya, Poorya, Pooria, Pouria, Pooriya, Porya lub Poria perskie imię męskie z korzeniem awestyckim Pouruyô, co oznacza: pierwszy; przede wszystkim; najstarszy. Wśród znanych osób z nazwiskiem: Pouria Alami (ur. 1983), irańska pisarka Pouria Fayazi (ur. 1993), irańska piłkarka siatkówki Pouria Norouzian (ur. 1992), irańskie strzelaninę sportowe Pouria Poursorkh (ur. 1976), irański aktor Pourya-ye Vali (ur. 1322), perskie mistrz pahlevani i...</p>", "Phan Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Phan</b>.</p><p>Phan może być: Họ Phan, rodzina mieszkańców Wietnamu, Chin i Korei Północnej Huyện Phan (Tajówki: อําเภอพาน), prowincji Chiang Rai, Tajlandii Xan Phan, prowincji Yang Minh Châu, prowincja Tsinh Ninh, Wietnam rzeka Phan, nazwy dwóch rzek w Pyongyang i Vịnhúc, Wietnamy</p>", "Penczo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pencho</b>.</p><p>Pencho (bułgarski: Пенчо) to męskie imię. Wśród nich są: Pencho Georgiev (1900-1940), bułgarski malarz, scenograf i ilustrator Pencho Slaveykov (1866-1912), bułgarski poeta Pencho Vichev (ur. 1952), bułgarański strzelca sportowy olimpijski Pencho Zlatev (1881-1948), bułgariański generał i polityk Pencho, postać w 1920 roku w brodowskiej sztuce Spanish Love</p>", "Paweł Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paweł</b>.</p>Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "Pauli": "<p>Pauli to nazwisko i także fińskie męskie nazwisko (variant Paul) i może odnosić się do:</p>", "Pierre Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pei": "<p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Priyankara": "<p>Priyankara to zarówno imię, jak i nazwisko. Znani ludzie z nazwiskiem to: Priyankara Rathnayake (ur. 1964), Sri Lankaniecki aktor Priyankara Silva (ur. 1975), Sri Lanka kryker Priyankara Wickramasinghe (ur. 1977), Sri Lankowy kryker Jagath Priyankara (ur. 1979), Sri Lanki polityk Nuwan Priyankara</p>", "Pablo Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Pierre-Olivier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Petrow": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Petrov</b>.</p><p>Petrow, Wszewolód Aleksejewicz (21 lutego 1896 - 1955) - sowiecki paleobotanin, jeden z pionierów sowieckiej metody sporu-polczu, kandydat na naukę biologiczne, депутат Petrogradskiego Rządowego Rady Leningradu w latach 1928 - 1931.</p>", "Pencho": "<p>Pencho (bułgarski: Пенчо) to męskie imię. Wśród nich są: Pencho Georgiev (1900-1940), bułgarski malarz, scenograf i ilustrator Pencho Slaveykov (1866-1912), bułgarski poeta Pencho Vichev (ur. 1952), bułgarański strzelca sportowy olimpijski Pencho Zlatev (1881-1948), bułgariański generał i polityk Pencho, postać w 1920 roku w brodowskiej sztuce Spanish Love</p>", "Pitamber": "<p>Pitamber może odnosić się do: Pitamber Das, indyjski polityk Pitambar Tarai, poet Oriya Pitambar Deva Goswami, asymiecki reformator społeczny Pitambar Charairongba, hinduistyczny władca Manipur Pitambar Paswan, indyjskiego polityka Nilamber-Pitamber University w Jharkhand Pitambar, 1992 Bollywood film Pitambar Rozdział 1, film nepalijski.</p>", "Pär": "<p>Pär to imię, skandynawska forma Piotra. Do wybitnych osób z tym nazwiskiem należą: Pär Arlbrandt (ur. 1982), szwedzki były profesjonalny hokejista na lodzie Pär Arvidsson (ur. 1960), były pływacz motyli z Szwecji Pär Asp (ur. 1982), emerytowany szwedzkiej piłkarz piłkarza Pär Bäcker (ur. 1982, szwedzka profesjonalna hokejistka na lodzie Aron Borg Pär (1776-1839), szwedski pedagog i pionier edukacji dla ślepych i głuchych Pär...</p>", "Paul-Louis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Pierre-Alexandre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Punjab": "Nazwa <i>Pendżab</i>, oznaczająca „Krainę Pięciu Rzek”, wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, gdzie <i>panj</i> oznacza „pięć”, a <i>āb</i> – „woda”. Pięć rzek Pendżabu to rzeki <a href=\"https://pl.wikipedia.org/wiki/Dorzecze\" target=\"_blank\" rel=\"noopener noreferrer\">dorzecza</a> <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indusu</a>: <a href=\"https://pl.wikipedia.org/wiki/Bjas_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Bjas</a>, <a href=\"https://pl.wikipedia.org/wiki/%C4%86anab\" target=\"_blank\" rel=\"noopener noreferrer\">Ćanab</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C5%BAhelam_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Dźhelam</a>, <a href=\"https://pl.wikipedia.org/wiki/Rawi\" target=\"_blank\" rel=\"noopener noreferrer\">Rawi</a> i <a href=\"https://pl.wikipedia.org/wiki/Satled%C5%BA\" target=\"_blank\" rel=\"noopener noreferrer\">Satledź</a>.", "Petro-Pavlo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petro</b>.</p><p>Petro to męskie imię, nazwisko i starożytne rzymskie nazwisko. Może odnosić się do:</p>", "Pierre Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pedro Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Platoni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Platon</b>.</p>Wzrost popularności myśli Platona oraz istotne postępy w badaniach nad jego tekstami zbiegały się z ważnymi przełomami w <a href=\"https://pl.wikipedia.org/wiki/Historia_filozofii_(nauka)\" target=\"_blank\" rel=\"noopener noreferrer\">historii filozofii i nauki</a>, szczególnie w okresie <a href=\"https://pl.wikipedia.org/wiki/Renesans\" target=\"_blank\" rel=\"noopener noreferrer\">renesansu</a> we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> oraz w <a href=\"https://pl.wikipedia.org/wiki/O%C5%9Bwiecenie_(epoka)\" target=\"_blank\" rel=\"noopener noreferrer\">oświeceniu</a> i <a href=\"https://pl.wikipedia.org/wiki/Romantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">romantyzmie niemieckim</a>. Jego metaforę jaskini eksploatuje późniejsza filozofia i kultura aż po XX-wieczną <a href=\"https://pl.wikipedia.org/wiki/Teoria_krytyczna\" target=\"_blank\" rel=\"noopener noreferrer\">teorię krytyczną</a>, <a href=\"https://pl.wikipedia.org/wiki/Alienacja\" target=\"_blank\" rel=\"noopener noreferrer\">teorię alienacji</a> człowieka, <a href=\"https://pl.wikipedia.org/wiki/Egzystencjalizm\" target=\"_blank\" rel=\"noopener noreferrer\">egzystencjalny</a> dyskurs autentyczności, <a href=\"https://pl.wikipedia.org/wiki/Psychoanaliza\" target=\"_blank\" rel=\"noopener noreferrer\">psychoanalizę</a>, czy nawet popkulturę, czego przykładem są filmy <i><a href=\"https://pl.wikipedia.org/wiki/Matrix\" target=\"_blank\" rel=\"noopener noreferrer\">Matrix</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Oni_%C5%BCyj%C4%85\" target=\"_blank\" rel=\"noopener noreferrer\">Oni żyją</a></i> oraz twórczość <a href=\"https://pl.wikipedia.org/wiki/Bill_Hicks\" target=\"_blank\" rel=\"noopener noreferrer\">Billa Hicksa</a>. Jego dialogowi filozoficznemu <i><a href=\"https://pl.wikipedia.org/wiki/Kratylos_(dialog)\" target=\"_blank\" rel=\"noopener noreferrer\">Kratylos</a></i> przypisuje się znaczenie językoznawcze, gdyż porusza on problematykę związku między słowami a <a href=\"https://pl.wikipedia.org/wiki/Element_znaczony\" target=\"_blank\" rel=\"noopener noreferrer\">treściami oznaczanymi</a>. Platon bywa uważany za założyciela <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a>.", "Polina": "<b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Pablo Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Pablo Emilio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Pimen": "<b>Pimen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Zostało utworzone od rzeczownika <i>poimën</i>, który znaczy „pasterz, nauczyciel”.", "Parveen Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Parveen</b>.</p><p>Parveen (persk: پروین) to perskiej kurdyjskiej nazwy, która oznacza Plejady. Jest powszechnie stosowany w Iranie, Afganistanie, Tadżykistanie, Pakistanie i Indiach.</p>", "Panayot": "<p>Panayot (bułgarski: Панайот, albanski: Panajot) jest nazwą pochodzącą z greckiego Panagiotis. Rumuński odpowiednik to Panait.</p>", "Prashant Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Prashant</b>.</p><p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Petru-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Premasiri": "<p>Premasiri to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Premasiri Khemadasa (1937-2008), Sri Lankanski kompozytor muzyczny Halambage Premasiri (1962-2016), Sri Lankanki kryketers Lionel Premasiri, Sri Lankanin polityk P.</p>", "Polikarpe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Polikarp</b>.</p><b>Polikarp</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>polykarpos</i> oznaczającego „płodny”.", "Per-Olof": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Per</b>.</p><p>Per: per - łaciński pretekst, odpowiadający słowom ⁇ ceрез ⁇ , ⁇ skvoзь ⁇ , ??po ⁇ lub ⁇ wzdłuż ⁇; część oznaczeń naukowych (np. per capita) i krytycznych fraz (np., per aspera ad astra). PeR - lotyjski pop-grupowy, założony w 2007 roku.</p>", "Paulina": "<b>Paulina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Paulin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulin</a>. Oznacza „należąca do <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Pawła</a>”, lub „pochodząca od Pawła”. Pochodzi od imienia <a href=\"https://pl.wikipedia.org/wiki/Paula\" target=\"_blank\" rel=\"noopener noreferrer\">Paula</a>, które może być dla niego również zdrobnieniem.", "Przedpełk": "<b>Przedpełk</b>, <b>Przedpołk</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Przed-</i> („przed\", ale też „naj”, „przez” i wiele innych) i <i>-pełk</i>, <i>-połk</i> („regiment wojska, pułk”). Mogło oznaczać „stawiający wyżej pułk, wojsko” lub też „ten, który dowodzi pułkiem” albo „ten, który jest lepszy od całego pułku”.", "Przecław": "<b>Przedsław</b>, <b>Przecław</b>, <b>Przecsław</b>, <b>Przesław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Przed-</i> (pierwszy człon posiadał wiele różnych znaczeń, zależnych od znaczenia drugiego członu imienia) i <i>-sław</i> („sława”). Imię notowane w Polsce od 1153 roku. Mogło oznaczać „ten, który stawia sławę ponad inne rzeczy”, „stawiający wyżej sławę”. Możliwe staropolskie zdrobnienia to: Przech, Przechno, Przeczek, Przeczko, Przeczk, Przeczka (masc.), Przeczeń, Przeczno, Przesz, Przeszek, Przeszko.", "Polian": "<b>Polian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, którego patronem jest św. Polian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Nemezjan\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezjanem</a>, <a href=\"https://pl.wikipedia.org/wiki/Datyw\" target=\"_blank\" rel=\"noopener noreferrer\">Datywem</a>, <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksem</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjuszem</a> (Lucjuszem), <a href=\"https://pl.wikipedia.org/wiki/Wiktor\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktorem</a> i Liteuszem (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Pedro Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Paul John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Perykles": "<b>Perykles</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Περικλῆς, „otoczony chwałą”; ur. ok. <a href=\"https://pl.wikipedia.org/wiki/495_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">495 p.n.e.</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/429_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">429 p.n.e.</a>) – ateński polityk, mąż stanu, retor oraz reformator <a href=\"https://pl.wikipedia.org/wiki/Demokracja_ate%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">demokracji ateńskiej</a>.", "Paweł Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paweł</b>.</p>Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "Pallav": "<p>Pallav (pल्लव w języku sanskrytycznym) to hinduskie imię. Oznacza to \"nowo narodzone liście\" każdego drzewa.</p>", "Petru-Pavel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Phillippe": "<p>Phillippe to zarówno imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Pierre-François": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Patience": "<p>Patience (z angielskiego - ⁇ Tolerance ⁇) - piąty i ostatni album studiów brytyjskiego piosenkarza pop- George'a Michaela, wydany 18 marca 2004 roku na wytwórniach Aegean, Sony Music i Epic.</p>", "Pierre Henri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pola": "<b>Pola</b> – zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolonia\" target=\"_blank\" rel=\"noopener noreferrer\">Apolonia</a>. Zaczęło być nadawane jako samodzielne imię. Być może usamodzielniła się pod wpływem pomieszania zdrobnienia Apolonii z imieniem <a href=\"https://pl.wikipedia.org/wiki/Paula\" target=\"_blank\" rel=\"noopener noreferrer\">Paula</a>, wymawianym w niektórych językach jako Pola. Wśród imion nadawanych nowo narodzonym dzieciom, Pola zajmuje 11. miejsce w grupie imion żeńskich.", "Peter Thomas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Peter</b>.</p><p>Peter (niemiecki Peter) - osobiste imię (variant nazwy Piote), nazwisko i nazwisko.</p>", "Paul Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Piotr Franciszek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pavlo-Bohdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pavlo</b>.</p><p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Pattrick": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patrick</b>.</p><p>Patrick (ang. Patrick) - męskie imię pochodzące od łacińskiego.</p>", "Patxi": "<p>Patxi jest męskim imieniem w obszarze języka baskiego w północnej Hiszpanii i południowo-zachodniej Francji, ale częściej jest to pseudonim dla tych, którzy oficjalnie nosili imię Francisco (lub François w strefie francuskiej, ostatecznie krewni Franciszka); oryginalnym odpowiednikiem baskickim był Frantzisko, ale rzadko wybierano to jako imię pierwotne przez rodziców w czasach nowoczesnych, a wraz z Patxi zakazano dawania niemowlękom w ramach polityki językowej frankoizmu...</p>", "Paula": "<b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Phi Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Phi</b>.</p><b>Phi</b> (<b>fi</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;φῖ, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>φι</b>, pisana <b>Φφ</b> lub <b>ϕ</b>) – dwudziesta pierwsza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/500_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">500</a>.", "Peace": "<p>⁇ Peace ⁇ (w tłumaczeniu z angielskiego - ⁇ Mir ⁇) - 47-y single brytyjskiej grupy Depeche Mode i drugi single z ich dwunastego albumu Sounds of the Universe.</p>", "Patrick John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Patrick</b>.</p><p>Patrick (ang. Patrick) - męskie imię pochodzące od łacińskiego.</p>", "Pedro Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pierre-Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Piotr Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Piatro": "<p>Piatro to białoruskie męskie imię, równoważne angielskiej Piotra. Jest on nosiony przez: Piatro Chatuloŭ, białoruskiego krytykę literatury zabity w 1937 r. w masowej egzekucji Białorusi przez Stalina Piatro Kravchanka (ur. 1950), białoruski polityk, dyplomat, politolog i historyk, ostatni minister spraw zagranicznych Białoruski SSR i pierwszy minister spraw zag zagranicznych Bieloruski Piatro Sadoŭski (ur. 1941), białorski lingwist,...</p>", "Paul Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Pierre Andre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Paul-Antoine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Piotr Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pedro Julio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Prakash Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Prakash</b>.</p><p>Prakash jest powszechną męską nazwą i nazwą w Azji Południowej, szeroko stosowaną w Nepalu, Indiach i Sri Lance. Słowo prakash pochodzi z sanskrytu prakāśa, co oznacza \"światło jasne\" lub \"świetło słońca\" lub \"swiatło księżyca\" lub \"Światło\", z połączenia pra oznacza \"za\" i kāśa oznacza \"świetlanie\".</p>", "Piotr Jacek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pierre-Vincent": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Phi Hung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Phi</b>.</p><b>Phi</b> (<b>fi</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;φῖ, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>φι</b>, pisana <b>Φφ</b> lub <b>ϕ</b>) – dwudziesta pierwsza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/500_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">500</a>.", "Ping-Hung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ping</b>.</p><p>Ping - użyteczność do sprawdzenia integralności i jakości połączeń w sieciach na podstawie TCP/IP, a także nazwy użytkowej zapytania. Utilito wysyła ICMP Echo-Request do wskazanego węzła i rejestruje otrzymane ICMP Echo -Reply.</p>", "Parvizi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Parviz</b>.</p><p>Parvēz, Pērvaz, Parviz lub Parvīs (perskiego: پرویز, پرویز w Nastaliq, oznacza \"szczęśliwy, zwycięski\"; średnioperskiego: plwyc Parvēz , również ʾplwyc Abarvēz/Aparvēz), to perskie imię męskie, w większości popularne w Iranie, Azji Środkowej, Azji Południowej i wśród Azerbejdżanów. Jest to również bardzo powszechne nazwisko.</p>", "Përparim": "<p>Përparim jest albanskim męskim imieniem i może odnosić się do:</p>", "Pinghua": "Według części badaczy gatunek rozwinął się jako komentarz opisujący wydarzenia na obrazach przedstawianych przez ulicznych opowiadaczy. Zachowało się dziewięć utworów tego gatunku, pochodzących z <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a>–<a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>. Są to długie opowiadania prozą o tematyce historycznej ze wstawkami poetyckimi. Najważniejsze z nich to <i>Sanguozhi pinghua</i> (<i>Opowieść o trzech królestwach</i>), będąca poprzedniczką późniejszych <i><a href=\"https://pl.wikipedia.org/wiki/Opowie%C5%9Bci_o_Trzech_Kr%C3%B3lestwach\" target=\"_blank\" rel=\"noopener noreferrer\">Opowieści o Trzech Królestwach</a></i>, oraz <i>Wudaishi pinghua</i> (<i>Opowieść o czasach panowania Pięciu Dynastii</i>).", "Pedro Francisco": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Prathamesh": "<p>Prathamesh to indyjskie imię męskie. Wśród znanych osób z nazwiskiem to: Prathamesh Dake (ur. 1991), indyjski kryker Prathameth Fuge (ur. 2002), indyjski łucznik Prathamesha Gawas (ur. 1994), indyjskie kryker prathamesh Jawkar (ur.</p>", "Pedro Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Panajoti": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Panajot</b>.</p><p>Panayot (bułgarski: Панайот, albanski: Panajot) jest nazwą pochodzącą z greckiego Panagiotis. Rumuński odpowiednik to Panait.</p>", "Pierre-Emmanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pranay Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pranay</b>.</p><p>Pranay jest hinduskim imieniem męskim, co oznacza \"miłość\" lub \"troskę\". Wśród znanych osób z tym nazwiskiem są: Pranay Chulet, indyjski przedsiębiorca, założyciel Quikr Pranay Gupte, amerykański-indyjski dziennikarz, autor i założyciel gazety Pranaya SJB Rana, nepalijski dziennikarka, autor i redaktor gazety Pranay Sahay, indyjskie policjant Pranay Sharma, indyjscy kryketacz Dasyam Pranay Bhasker, indyjska polityk Pranayraj Vangari,...</p>", "Przebor": "<b>Przebor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Prze-</i> („przez” i wiele innych znaczeń) i <i>-bor</i> („walczyć, zmagać się”). Być może oznaczało „tego, kto najlepiej walczy”.", "Pedro Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pimeni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pimen</b>.</p><b>Pimen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Zostało utworzone od rzeczownika <i>poimën</i>, który znaczy „pasterz, nauczyciel”.", "Paweł Emanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paweł</b>.</p>Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "Piotr Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Prince Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Prince</b>.</p><p>Prince Rogers Nelson (ang. Prince Rogers Nelson; 7 czerwca 1958[...], Minneapolis, Minnesota - 21 kwietnia 2016[...], Shanhaassen) - amerykański muzyk, piosenkarz, gitarzysta-wirtuoz, multiinstrumentalist, autor piosenek, kompozytor, producent, aktor, reżyser.</p>", "Pano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pan</b>.</p><p>Pan lub PAN może oznaczać: technika obliczeniowa: Sieć osobowa (ang. Personal Area Network) - sieć przekazywania danych łącząca osobiste urządzenia elektroniczne jednego użytkownika (telefony, kieszeni personalne komputery, smartfony, notebooky, bezprzewodowe armatury itp.</p>", "Pierre Jean Yves": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Petru-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Patrycja": "<b>Patrycja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskich imion <a href=\"https://pl.wikipedia.org/wiki/Patrycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Patrycy\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycy</a>, <a href=\"https://pl.wikipedia.org/wiki/Patryk\" target=\"_blank\" rel=\"noopener noreferrer\">Patryk</a>. Oznacza „szlachetnie urodzona, patrycjuszowska”. Wśród imion nadawanych nowo narodzonym dzieciom, Patrycja w 2017 r. zajmowała 58. miejsce w grupie imion żeńskich. W całej populacji Polek Patrycja zajmowała w 2017 r. 41. miejsce (166 497 nadań).", "Paul Michael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Petrus Johannes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petrus</b>.</p><p>Żółty kamienny zęb (lat. Petrus rupestris) - rodzaj morskiej ryby promieniowania rodziny sparowych, jedyny przedstawiciel rodu kamiennych zębów (Petrus).</p>", "Patryc": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patryk</b>.</p><b>Patryk</b> – oboczna, skrócona wersja imienia <a href=\"https://pl.wikipedia.org/wiki/Patrycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycjusz</a>, posiadającego też formę <a href=\"https://pl.wikipedia.org/wiki/Patrycy\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycy</a>. Pochodzenie i znaczenie: łacińskie: <i>patricius</i> – patrycjuszowski, szlachecki, szlachetnie urodzony, zasiadający w senacie. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Patrycja\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycja</a>.", "Pedro Nel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Paweł Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paweł</b>.</p>Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "P": "<b>P</b> (<i>pe</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>p</b>) – szesnasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, dwudziesta druga litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a> i oznacza głoskę [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">p</a>].", "Pierre J.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pedro Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pierre Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Paul-Emmanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Paweł Rajmund": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paweł</b>.</p>Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "Peter George": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Peter</b>.</p><p>Peter (niemiecki Peter) - osobiste imię (variant nazwy Piote), nazwisko i nazwisko.</p>", "Paule": "<p>Paule (Breton: Paoul) jest gminą w prowincji Côtes-d'Armor, w regionie Bretagne, północno-zachodni we Francji.</p>", "Paul Dexter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Piotr Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pierre Maurice": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Peter James": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Peter</b>.</p><p>Peter (niemiecki Peter) - osobiste imię (variant nazwy Piote), nazwisko i nazwisko.</p>", "Paul Michel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Peri": "<p>⁇ PERI ⁇ - jeden z największych na świecie producentów i dostawców ołobek i lasów budowlanych.</p>", "Petru-Călin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Panajot": "<p>Panayot (bułgarski: Панайот, albanski: Panajot) jest nazwą pochodzącą z greckiego Panagiotis. Rumuński odpowiednik to Panait.</p>", "Paul Bernard": "Urodził się w rodzinie architekta pochodzenia żydowskiego. W wieku 14 lat przeniósł się wraz z rodziną do Paryża i uczęszczał do <a href=\"https://pl.wikipedia.org/wiki/Lyc%C3%A9e_Condorcet\" target=\"_blank\" rel=\"noopener noreferrer\">Lycée Condorcet</a>. Po studiach prawniczych i służbie wojskowej rozpoczął pracę w administracji huty aluminium.", "Pedro Afonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Petro-Rostyslav": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petro</b>.</p><p>Petro to męskie imię, nazwisko i starożytne rzymskie nazwisko. Może odnosić się do:</p>", "Per Magnus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Per</b>.</p><p>Per: per - łaciński pretekst, odpowiadający słowom ⁇ ceрез ⁇ , ⁇ skvoзь ⁇ , ??po ⁇ lub ⁇ wzdłuż ⁇; część oznaczeń naukowych (np. per capita) i krytycznych fraz (np., per aspera ad astra). PeR - lotyjski pop-grupowy, założony w 2007 roku.</p>", "Ptolemeusz": "<b>Ptolemeusz</b>, <b>Ptolomeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Πτολεμαῖος), później <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowane</a>. Pierwotnie pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;πόλεμος („wojna”), a przymiotnik Πτολεμαῖος oznaczał „wojowniczy”.", "Paul Christian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Per Oscar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Per</b>.</p><p>Per: per - łaciński pretekst, odpowiadający słowom ⁇ ceрез ⁇ , ⁇ skvoзь ⁇ , ??po ⁇ lub ⁇ wzdłuż ⁇; część oznaczeń naukowych (np. per capita) i krytycznych fraz (np., per aspera ad astra). PeR - lotyjski pop-grupowy, założony w 2007 roku.</p>", "Paul Maurice": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Pjeter": "<p>Pjetër lub Për to albanianki męski imię, które jest krewnym Piotra, pochodzące ostatecznie od greckiego słowa petros, co oznacza \"kamień\" lub \" skała\". Nazwa może odnosić się do: Pjetër Arbnori (1936-2006), albańskiego polityka Pjetër Bogdani (1627-1689), albańskiego pisarza Pjetër Budi (1566-1622), albańskiego spisującego Pjetër Dungu (1908-1989), albańskiej muzyki Pjetër Gaci (1931-1995), albańskego kompozytora Pjetër Gjoka (1912-1982), albańskie aktora Pjetér Losha ...</p>", "Pavlo-Petro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pavlo</b>.</p><p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Pierre-Julien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Phelix": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Felix</b>.</p><p>Felix (lat. Felix - ⁇ płodny, owocny, szczęśliwy, dobrobytny, błogosławiony, bogaty) - imię męskie.</p>", "Przybyrad": "<b>Przybyrad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Przyby-</i> (\"przybyć, przybywać\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\"). Może oznaczać \"ten, z którym przybywa radość\".", "Pavlo-Vladyslav": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pavlo</b>.</p><p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Pascall": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pascal</b>.</p><p>Pascal - jeden z najbardziej znanych języków programowania, używany do nauczania programowania w wyższych klasach i na pierwszych kursach uczelni, jest podstawą dla szeregu innych języków.</p>", "Pinto": "<b>Pinto</b> – <a href=\"https://pl.wikipedia.org/wiki/Rasy_konia_domowego\" target=\"_blank\" rel=\"noopener noreferrer\">rasa</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">koni</a> pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">USA</a> i od 1963 uznawana za oddzielną rasę. Od 1956 hodowane pod okiem <i>Pinto Horse Association of America</i> (PtHA) pod kątem ubarwienia, harmonijnej budowy i chodów.", "Prashantha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Prashanth</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Prashant</b>.</p><p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Pubudu": "<p>Pubudu to imię. Poprzedni znani ludzie z imieniem: Pubudu Chandrasekara (ur. 1981), kryketar Sri Lanki Pubudu Chathuranga (ur. 1982), aktor Sri Lanki pubudu Dassanayake (ur. 1970), kryketer Kanady Pubudu Hasanka (ur. 1991), kryker Sri Lankipubudu Seneviratne (ur. 1980), kryketkarz Sri Lanki PUBudu Wickrama (ur. 1980, kryketer Sri Lanki)</p>", "Pasieka": "O istnieniu na ziemiach polskich pasieki już w czasach piastowskich świadczą liczne nazwy miejscowe, pierwsza zaś wzmianka pisemna o pasiece pochodzi z 1238 roku.", "Prodan": "<p>Prodan (bułgarski: Продан) to sławskie imię męskie (bułgarskie, serbskie i chorwackie), samo w sobie pasywne przymiot (prodan) od sławskiego prodati - \"sprzedać\", co oznacza \"sprzedawać\". Jest to zaświadczone w społeczeństwie bułgarskim i chorwackim od średniowiecza.</p>", "Panaiot": "<p>Panayot (bułgarski: Панайот, albanski: Panajot) jest nazwą pochodzącą z greckiego Panagiotis. Rumuński odpowiednik to Panait.</p>", "Petru-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Pedro-Luis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Parwiz": "<p>Parvēz, Pērvaz, Parviz lub Parvīs (perskiego: پرویز, پرویز w Nastaliq, oznacza \"szczęśliwy, zwycięski\"; średnioperskiego: plwyc Parvēz , również ʾplwyc Abarvēz/Aparvēz), to perskie imię męskie, w większości popularne w Iranie, Azji Środkowej, Azji Południowej i wśród Azerbejdżanów. Jest to również bardzo powszechne nazwisko.</p>", "Pablo Arturo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Peio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Paul Andrew": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Petru-Ciprian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Pietro Francesco": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pietro</b>.</p><p>Piotr (Pietro) - katolicki czołowy działacz IX wieku. Stał się presbyter cardinalis prawdopodobnie w konsistorii 875 roku.</p>", "Paul-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Patrick Czeslaw": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Patrick</b>.</p><p>Patrick (ang. Patrick) - męskie imię pochodzące od łacińskiego.</p>", "Piotr Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Peteris": "<p>Pēteris to łacińska męska nazwa. Jest krewnym nazwiska Petera i może odnosić się do: Pēteris Juraševskis (1872-1945), lotyjskiego polityka i byłego premiera Łotwy Pēteris Kalniņš (ur. 1988), lotyńskiego lutyżera i zawodnika olimpijskiego Pēteris Lauks (1902-1984), lotyjski obrońca piłki nożnej Pēteris Pētersons (1923-1998), lotyjskiej dramaturga, reżysera teatralnego i krytyka dramatyczna, teoretyka, tłumacza, dziennikarz i społecznościowy...</p>", "Pirmin": "Od jego imienia pochodzi nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemczech</a> – <a href=\"https://pl.wikipedia.org/wiki/Pirmasens\" target=\"_blank\" rel=\"noopener noreferrer\">Pirmasens</a>. W <i>De singulis libris canonicis scarapsus</i> autorstwa tego świętego znajduje się najwcześniejszy zapis <a href=\"https://pl.wikipedia.org/wiki/Apostolski_symbol_wiary\" target=\"_blank\" rel=\"noopener noreferrer\">apostolskiego symbolu wiary</a> w obecnej formie.", "Pierre-Frédéric": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Patrick Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Patrick</b>.</p><p>Patrick (ang. Patrick) - męskie imię pochodzące od łacińskiego.</p>", "Primitivo Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Primitivo</b>.</p><b>Primitivo</b>, <b>zinfandel</b>, <b>tribidrag</b>, <b>crljenak kaštelanski</b>, <b>kratošija</b> – <a href=\"https://pl.wikipedia.org/wiki/Wino_czerwone\" target=\"_blank\" rel=\"noopener noreferrer\">czerwony</a> <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">szczep</a> <a href=\"https://pl.wikipedia.org/wiki/Winoro%C5%9Bl_w%C5%82a%C5%9Bciwa\" target=\"_blank\" rel=\"noopener noreferrer\">winorośli właściwej</a>, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a>. Dopiero badania DNA pozwoliły ustalić, że wszystkie pięć nazw dotyczy tego samego szczepu. Nazwa <b>zinfandel</b> jest używana przede wszystkim w <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a>, natomiast chorwackie nazwy <b>crljenak kaštelanski</b> i <b>tribidrag</b> w ojczyźnie odmiany, choć np. Jancis Robinson próbuje spopularyzować najstarszą z nich, czyli tribidrag. <b>Primitivo</b> jest tradycyjnie uprawiane od XVIII wieku w <a href=\"https://pl.wikipedia.org/wiki/Apulia\" target=\"_blank\" rel=\"noopener noreferrer\">Apulii</a> („obcas” <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoch</a>). W połowie XIX wieku trafiło do Stanów Zjednoczonych i stało się tam znane pod nazwą 'Zinfandel' i jej wariantami. Odmiana jest uprawiana na ponad 10% winnic kalifornijskich. Nazwa primitivo jest traktowana przez <a href=\"https://pl.wikipedia.org/wiki/Instytut_Hodowli_Winoro%C5%9Bli_Geilweilerhof\" target=\"_blank\" rel=\"noopener noreferrer\">Instytut Hodowli Winorośli Geilweilerhof</a> jako podstawowa.", "Peres": "<b>Peres</b> lub <b>Fares</b> − postać biblijna z <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Juda_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Judy</a> i jego synowej <a href=\"https://pl.wikipedia.org/wiki/Tamar_(synowa_Judy)\" target=\"_blank\" rel=\"noopener noreferrer\">Tamar</a>. Jego bratem bliźniakiem był Zerach, a braćmi przyrodnimi <a href=\"https://pl.wikipedia.org/wiki/Er_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Er</a>, <a href=\"https://pl.wikipedia.org/wiki/Onan\" target=\"_blank\" rel=\"noopener noreferrer\">Onan</a> i <a href=\"https://pl.wikipedia.org/wiki/Szela\" target=\"_blank\" rel=\"noopener noreferrer\">Szela</a>. Od Peresa pochodzi ród Parsytów.", "Pratapsinh": "<p>Pratapsinh to męskie imię. Znani ludzie z imieniem Prabhatsinh Pratapsinh Chauhan (ur. 1941), indyjski polityk Pratapsinch Jadhav (ur. 1945), indyjscy dziennikarz PratapsinH Mohite-Patil (1955-2015), indyjskie polityk</p>", "Pablo Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Psalm": "<b>Psalm</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ψαλμός – psalmós</i>, pochodzi od <i>psallein</i> i oznacza śpiew przy akompaniamencie instrumentu strunowego zwanego psalterionem) – liryczny utwór modlitewny, rodzaj <a href=\"https://pl.wikipedia.org/wiki/Pie%C5%9B%C5%84_(gatunek_literacki)\" target=\"_blank\" rel=\"noopener noreferrer\">pieśni</a> <a href=\"https://pl.wikipedia.org/wiki/Religia\" target=\"_blank\" rel=\"noopener noreferrer\">religijnej</a> o podniosłym charakterze, którego adresatem jest zazwyczaj <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a>, rzadziej <a href=\"https://pl.wikipedia.org/wiki/Cz%C5%82owiek_rozumny\" target=\"_blank\" rel=\"noopener noreferrer\">człowiek</a>. Ze względu na treść wyróżnia się psalmy dziękczynne, błagalne, <a href=\"https://pl.wikipedia.org/wiki/Psalmy_pokutne\" target=\"_blank\" rel=\"noopener noreferrer\">pokutne</a>, <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorocze</a>, pochwalne, <a href=\"https://pl.wikipedia.org/wiki/Patriotyzm\" target=\"_blank\" rel=\"noopener noreferrer\">patriotyczne</a>, żałobne.", "Pedro Angel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pedro Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Ptolomeusz": "<b>Ptolemeusz</b>, <b>Ptolomeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Πτολεμαῖος), później <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowane</a>. Pierwotnie pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;πόλεμος („wojna”), a przymiotnik Πτολεμαῖος oznaczał „wojowniczy”.", "Paweł Tomasz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paweł</b>.</p>Imię to należało na przestrzeni wieków do najpopularniejszych imion w Polsce. Świadczy o tym, obok odnotowanych wyżej zdrobnień, m.in. fakt pochodzenia od imienia Paweł wielu nazwisk i nazw miejscowych. Nazwiska pochodzące od tego imienia to m.in.: <i>Pach</i>, <i>Pachota</i>, <i>Pachowicz</i>, <i>Pachura</i>, <i>Pasiut</i>, <i>Pasiutek</i>, <i>Paszek</i>, <i>Paszkiewicz</i>, <i>Paszkowicz</i>, <i>Pawelec</i>, <i>Paweł</i>, <i>Pawełczyk</i>, <i>Pawełek</i>, <i>Pawełkiewicz</i>, <i>Pawełko</i>, <i>Pawlak</i>, <i>Pawlas</i>, <i>Pawlica</i>, <i>Pawliczak</i>, <i>Pawliczek</i>, <i>Pawliczuk</i>, <i>Pawlik</i>, <i>Pawlikiewicz</i>, <i>Pawlisiak</i>, <i>Pawlisz</i>, <i>Pawliszak</i>, <i>Pawluk</i>, <i>Pawlukiewicz</i>, <i>Pawlus</i>, <i>Pawliszkiewicz</i>, <i>Pawliśkiewicz</i>, <i>Pawłowicz</i> i in.", "Pilipe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pilip</b>.</p><p>Pilip to męskie imię, spokrewnione z Philipem. Może odnosić się do: Pilip Ballach Ó Duibhgeannáin (fl.</p>", "Pavlo-Volodymyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pavlo</b>.</p><p>Paul jest powszechnym łacińskim imieniem męskim w krajach i etniach z dziedzictwem chrześcijańskim (wschodnia prawosławia, katolicyzm, protestancka) i poza Europą, w chrześcianiach na całym świecie. Paweł - albo jego odmiany - może być nazwiskiem lub nazwiskiem.</p>", "Petru-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Pablo Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Patrice Claude": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Patrice</b>.</p><p>Patrice (pełna: Patrice Bart-Williams) - afro-niemiecki wykonawca w stylu reggi.</p>", "Prakash Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Prakash</b>.</p><p>Prakash jest powszechną męską nazwą i nazwą w Azji Południowej, szeroko stosowaną w Nepalu, Indiach i Sri Lance. Słowo prakash pochodzi z sanskrytu prakāśa, co oznacza \"światło jasne\" lub \"świetło słońca\" lub \"swiatło księżyca\" lub \"Światło\", z połączenia pra oznacza \"za\" i kāśa oznacza \"świetlanie\".</p>", "Petrus Paulus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petrus</b>.</p><p>Żółty kamienny zęb (lat. Petrus rupestris) - rodzaj morskiej ryby promieniowania rodziny sparowych, jedyny przedstawiciel rodu kamiennych zębów (Petrus).</p>", "Primitivo": "<b>Primitivo</b>, <b>zinfandel</b>, <b>tribidrag</b>, <b>crljenak kaštelanski</b>, <b>kratošija</b> – <a href=\"https://pl.wikipedia.org/wiki/Wino_czerwone\" target=\"_blank\" rel=\"noopener noreferrer\">czerwony</a> <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">szczep</a> <a href=\"https://pl.wikipedia.org/wiki/Winoro%C5%9Bl_w%C5%82a%C5%9Bciwa\" target=\"_blank\" rel=\"noopener noreferrer\">winorośli właściwej</a>, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a>. Dopiero badania DNA pozwoliły ustalić, że wszystkie pięć nazw dotyczy tego samego szczepu. Nazwa <b>zinfandel</b> jest używana przede wszystkim w <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a>, natomiast chorwackie nazwy <b>crljenak kaštelanski</b> i <b>tribidrag</b> w ojczyźnie odmiany, choć np. Jancis Robinson próbuje spopularyzować najstarszą z nich, czyli tribidrag. <b>Primitivo</b> jest tradycyjnie uprawiane od XVIII wieku w <a href=\"https://pl.wikipedia.org/wiki/Apulia\" target=\"_blank\" rel=\"noopener noreferrer\">Apulii</a> („obcas” <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoch</a>). W połowie XIX wieku trafiło do Stanów Zjednoczonych i stało się tam znane pod nazwą 'Zinfandel' i jej wariantami. Odmiana jest uprawiana na ponad 10% winnic kalifornijskich. Nazwa primitivo jest traktowana przez <a href=\"https://pl.wikipedia.org/wiki/Instytut_Hodowli_Winoro%C5%9Bli_Geilweilerhof\" target=\"_blank\" rel=\"noopener noreferrer\">Instytut Hodowli Winorośli Geilweilerhof</a> jako podstawowa.", "Paul-Henri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Prashant Mohan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Prashant</b>.</p><p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Philibert": "<p>Philibert może odnosić się do następujących osób:</p>", "Perparim": "<p>Përparim jest albanskim męskim imieniem i może odnosić się do:</p>", "Prashanth Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Prashanth</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Prashant</b>.</p><p>Prashant lub Prasant jest powszechną nazwą męską w Azji Południowej. Pochodzi od słowa \"shanth\", co oznacza cierpliwość, spokój, spokojnost lub spokojnost.</p>", "Pedro Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pedro</b>.</p><p>Pedro (hisz. Pedro), Pedro (port.</p>", "Pjetër": "<p>Pjetër lub Për to albanianki męski imię, które jest krewnym Piotra, pochodzące ostatecznie od greckiego słowa petros, co oznacza \"kamień\" lub \" skała\". Nazwa może odnosić się do: Pjetër Arbnori (1936-2006), albańskiego polityka Pjetër Bogdani (1627-1689), albańskiego pisarza Pjetër Budi (1566-1622), albańskiego spisującego Pjetër Dungu (1908-1989), albańskiej muzyki Pjetër Gaci (1931-1995), albańskego kompozytora Pjetër Gjoka (1912-1982), albańskie aktora Pjetér Losha ...</p>", "Paul Anthony": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Petru-Emanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Pierre M.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Paul Junior": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Pablo Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Pierre Francis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pierre Georges": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Prawit": "<p>Prawit i Pravit są rumowniami tajskiego męskiego imiona ประวิตร i ประวิทย์ (które są homofony). Prawit Wongsuwon, generał wojskowy i polityk Prawit Prariwanta, piłkarz Pravit Rojanaphruk, dziennikarz Pravit Wasoontra, piłkacz Pravit Suwanwichit, bokser</p>", "Pankaj Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pankaj</b>.</p><p>Pankaj jest powszechną nazwą w Indiach i Nepalu. Jego korzenie pochodzą z słowa sanskrytycznego pankaja, które odnosi się do kwiatu lotosu.</p>", "Pablo Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pablo</b>.</p><p>⁇ Pablo ⁇ - piosenka rosyjskiego rapperka i muzyka Morgenschtern z czwartego albumu studiowego Morgenschen Million Dollar: Happiness, wydanego 21 maja 2021 roku na wytwórni Atlantic Records Russia.</p>", "Pierre François": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Paul George": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paul</b>.</p><p>Paul (niem. Paul) - niemieckie imię i nazwisko mężczyzny pochodzenia łacińskiego, wariant nazwiska Pavel.</p>", "Piotr Antoine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pei-Chieh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Paramon": "<b>Paramon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, gr. <i>Παραμονος</i>. Wywodzi się od słowa <i>παραμονη (paramone)</i> oznaczającego \"stałość, wytrzymałość\". Wśród patronów - św. Paramon (III wiek).", "Peter Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Peter</b>.</p><p>Peter (niemiecki Peter) - osobiste imię (variant nazwy Piote), nazwisko i nazwisko.</p>", "Pomponiusz": "<b>Pomponiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pompatyczny, wspaniały\". Istnieje przynajmniej dwóch świętych patronów tego imienia.", "Peter P.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Peter</b>.</p><p>Peter (niemiecki Peter) - osobiste imię (variant nazwy Piote), nazwisko i nazwisko.</p>", "Pandi": "<p>Pandi może odnosić się do: Pandi, Bulacan, Filipiny Pandi, Cundinamarca, Kolumbii Pandi (film), indyjski film w języku tamilowym Pandi (legendarna istota), stworzenie średniowiecznego bestiary Pandi (maskot), symbol Letnich Olimpiad Młodzieżowych Pandi Melam 2018, indyjski koncert klasycznych perkusji lub ansambl PANDI, sponsor indonezyjskiego kodu kraju internetowego .id</p>", "Petru-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Petru</b>.</p><p>Petru jest nazwiskiem i może odnosić się do: Petru I z Mołdawii (Petru Mușat, 1375-1391), władcy Mołdawy Petru Aron (zmarł 1467), władcy Modowy Petru Bălan (ur. 1976), rumuńskiego piłkarza rugby Petru Cărare (1935-2019), pisarza z Mołdowy Petru Cercel (ur. 1590), województwa Waliki, wielojęzyczka Petru Dugulescu (1945-2008), rumuńskiej baptystów pastor, poeta i polityk Petru Filip (ur. 1955), obecnego burmistrza gminy...</p>", "Pierre-André": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pierre</b>.</p><p>Jean-Baptiste Louis Pierre (francuski: Jean-Battiste Louis Pierre)  Jean Baptiste Louis Pierre lub fr.</p>", "Pejo": "<p>Pejo to męskie imię w języku serbo-chorwackim, maleńka forma imienia Petar. Znanymi osobami z nazwiska są: Pejo Ćošković (ur. 1952), bosnijski średniowieczny Pejo Kuprešak (ur. 1992), chorwacki piłkarz</p>", "Piotr Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Pelagia": "<b>Pelagia</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, pochodzące od przymiotnika <i>pelagios</i>, oznaczającego „morski”. Męskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Pelagiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagiusz</a>.", "Pamela": "<b>Pamela</b> – imię żeńskie pochodzenia literackiego, wymyślone przez <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI-wiecznego</a> poetę <a href=\"https://pl.wikipedia.org/wiki/Philip_Sidney\" target=\"_blank\" rel=\"noopener noreferrer\">Philipa Sidneya</a> na użytek poematu <i>Arkadia</i> w 1590 roku. W 1740 roku <a href=\"https://pl.wikipedia.org/wiki/Samuel_Richardson\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel Richardson</a> uczynił osobę o tym imieniu tytułową bohaterką powieści <i>Pamela, czyli Cnota nagrodzona</i>. Powieść tę sparodiował szybko <a href=\"https://pl.wikipedia.org/wiki/Henry_Fielding\" target=\"_blank\" rel=\"noopener noreferrer\">Henry Fielding</a>, pisząc swój debiut literacki <i><a href=\"https://pl.wikipedia.org/wiki/An_Apology_for_the_Life_of_Mrs._Shamela_Andrews\" target=\"_blank\" rel=\"noopener noreferrer\">An Apology for the Life of Mrs. Shamela Andrews</a></i>, przyczyniając się do upowszechnienia imienia Pamela.", "Patricia": "<p>Patricia może odnosić się do: Patricia Rodriguez 436 Patricia</p>", "Palina": "<p>Palina (do 2018 roku - Polina Republika (Palina Rządowa); prawdziwe imię - Polina Juryjevna Pololnejczak, biały. Palinę Jurewną Palanayczyc; rod.</p>", "Petronela": "<b>Petronela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pierwotnie będące formą zdrobniałą imienia <a href=\"https://pl.wikipedia.org/wiki/Petronia\" target=\"_blank\" rel=\"noopener noreferrer\">Petronia</a>.", "Prakseda": "<b>Prakseda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, powstało od wyrazu <i>praksis</i> (<i>działanie</i>). Prakseda <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/21_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">21 lipca</a>.", "Petra": "<b>Petra</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> πέτρα, <i>pétra</i>, „skała”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> البتراء, <i>al-Batrāʾ</i>) – ruiny miasta <a href=\"https://pl.wikipedia.org/wiki/Nabatejczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Nabatejczyków</a>, którego rozkwit miał miejsce w czasach antycznych, od <a href=\"https://pl.wikipedia.org/wiki/III_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">III w. p.n.e.</a> do <a href=\"https://pl.wikipedia.org/wiki/I_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">I w. n.e.</a> Petra była wtedy stolicą królestwa Nabatejczyków. Znajduje się w południowo-zachodniej <a href=\"https://pl.wikipedia.org/wiki/Jordania\" target=\"_blank\" rel=\"noopener noreferrer\">Jordanii</a>. Położona jest w skalnej dolinie, do której prowadzi jedna wąska droga wśród skał – wąwóz <a href=\"https://pl.wikipedia.org/wiki/As-Sik\" target=\"_blank\" rel=\"noopener noreferrer\">As-Sik</a>. Petra słynie z licznych budowli wykutych w skałach. Sami Nabatejczycy zwali Petrę <i>Rqm</i> (Rakmu), co oznacza „wielobarwna”.", "Pauline": "<p>Pauline avibella (lat.) - gatunek wymarłych raków z rodziny Cylindroleberididae klasy raków, typowy i jedyny w rodzeniu Pauline. Żyły w epoce węlowej okresu silurskiego.</p>", "Pia": "Zostało ono utworzone jako żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Pius</a>, którego pierwotne znaczenie to „pobożny, uczciwy, oddany”.", "Paloma": "<b>Paloma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a>. Wywodzi się od słowa <i>paloma</i> oznaczającego \"gołębica\".", "Przemysława": "<b>Przemysława</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Przemys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Przemysław</a> – formy staropolskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <b><a href=\"https://pl.wikipedia.org/wiki/Przemys%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Przemysł</a></b>, utworzonej, kiedy świadomość jego pochodzenia zatarła się i błędnie zostało ono uznane za imię kończące się członem <i>-sław</i> (zamiast <i>-mysł</i>). W źródłach poświadczone w XII wieku (1155–1156).", "Penelope": "<p>Penelope to bezpłatny, wolno dystrybuowany program do obsługi wiadomości e-mail i grup wiadomości oparty na Eudora Mail i Thunderbird. Później została przemianowana na Eudora OSE.</p>", "Priscilla": "<p>Priscilla (francuski Priscilla [pʁisiˈlɑ], naszt.</p>", "Phoebe": "<p>Phoebe (lat. Phoebe, z tytułu titaniady Phoebe) - rodzaj drzewnych roślin rodziny Lavrów (Lauraceae), rozpowszechniony w regionach tropycznych i subtropycznych Azji.</p>", "Pilar": "<p>Pilar to miasto w Brazylii. Miasto to ma powierzchnię 248,98 km2, liczba ludności w 2007 roku wynosi 30652 osób, a jego gęstość 123,11 osób/km2.</p>", "Patrycia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patricia</b>.</p><p>Patricia może odnosić się do: Patricia Rodriguez 436 Patricia</p>", "Pnina": "<p>Pnina (Hebrajskie: פְּנִינָּה lub פְּנוִנָּּה) jest żydowska kobieca nazwa, co oznacza \"perlu\" w języku hebrajskim. Do innych literatury należą Penina, Penina i Penina.</p>", "Palmira": "<b>Palmira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>.", "Princess": "<p>Księżniczka - jeden z najwyższych tytułów przedstawicieli arystokracji, córka króla i królowej. Może również oznaczać:</p>", "Poppy": "<p>Moraia Rose Pereira (ang. Moriah Rose Pereira; rodzaj.</p>", "Pearl": "<p>Pearl to czwarty album studiowy Janice Joplin, nagrany przez producenta Paula Rothschild w wrześniu - październiku 1970 roku i wydany przez Columbia Records 11 stycznia 1971 roku, cztery miesiące po śmierci piosenkarki.</p>", "Paige": "<b>Paige</b> – angielskie imię, odmiana imienia \"Page\", spotykana jest także wersja \"Payge\". Współcześnie imię zazwyczaj jest nadawane kobietom, choć tradycyjnie uważane jest za \"unisex\".", "Peli̇n": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pelina</b>.</p><b>Pelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pelin\" target=\"_blank\" rel=\"noopener noreferrer\">Pelin</a>. Jego patronem jest św. Pelin, zm. w 361 r., pod rządami <a href=\"https://pl.wikipedia.org/wiki/Julian_Apostata\" target=\"_blank\" rel=\"noopener noreferrer\">Juliana Apostaty</a>.", "Pelin": "<b>Pelin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone z gr. przymiotnika <i>pélinos</i> — \"ciemny, czarny, Murzyn\". Patronem tego imienia jest św. Pelin, biskup <a href=\"https://pl.wikipedia.org/wiki/Brindisi\" target=\"_blank\" rel=\"noopener noreferrer\">Brindisi</a>, zm. w 361 r., pod rządami <a href=\"https://pl.wikipedia.org/wiki/Julian_Apostata\" target=\"_blank\" rel=\"noopener noreferrer\">Juliana Apostaty</a>.", "Panagiota": "<p>Panagiota (grecki: Παναγιώτα), inaczej pisana jako Panayiota, jest kobiece greckie imię. Pochodzi z greckiego epitetu Panagia (grecki: Παναγία), co oznacza \"Wszyscy święci\", dla Maryi.</p>", "Poonam": "<p>Poonam lub Punam (Hindi: पूनम) to hindusko-sanskrityckie imiona indyjskie głównie kobiece, co oznacza \"pełny księżyc\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Poliana": "<b>Poliana</b>, <b>Polianna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Polian\" target=\"_blank\" rel=\"noopener noreferrer\">imienia męskiego</a>, którego patronem jest św. Polian, wspominany razem ze św. Nemezjanem, <a href=\"https://pl.wikipedia.org/wiki/Datyw\" target=\"_blank\" rel=\"noopener noreferrer\">Datywem</a>, <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksem</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjuszem</a> (Lucjuszem), <a href=\"https://pl.wikipedia.org/wiki/Wiktor\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktorem</a> i Liteuszem (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Patima": "<p>Patima to rodzaj roślin kwiatowych w rodzinie Rubiaceae.</p>", "Princessa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Princess</b>.</p><p>Księżniczka - jeden z najwyższych tytułów przedstawicieli arystokracji, córka króla i królowej. Może również oznaczać:</p>", "Perpetua": "<b>Perpetua</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>perpetuus</em> oznaczającego „nieprzerwany, ciągły”. W Polsce imię to jest notowane co najmniej od 1621 roku, jednakże poza kręgami zakonnymi nie&#160;występuje.", "Pandora": "<p>Pandora może oznaczać: Pandora (od 1878 roku - Jeannette) - statek zbudowany dla brytyjskiej floty wojennej w 1860 roku, dwa razy uczestniczył w ekspedycjach Alena Janga na Arktyce i zmiażdżony w lodzie podczas ekspedycji George'a Delonga w 1881 roku. Pandora to dom biżuterii założony w Kopenhadze (Danii) w 1982 roku.</p>", "Panajota": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Panajot</b>.</p><p>Panayot (bułgarski: Панайот, albanski: Panajot) jest nazwą pochodzącą z greckiego Panagiotis. Rumuński odpowiednik to Panait.</p>", "Paula Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Prisca": "<p>Przyska (lat. Prisca, ok.</p>", "Placyda": "<b>Placyda</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Placyd\" target=\"_blank\" rel=\"noopener noreferrer\">Placyd</a>. Zdrobnienia to Cytka, Cysia, Platusia. Istnieją święte i błogosławione tego imienia.", "Polly": "<p>⁇ Polly ⁇ (z angielskiego - ⁇ Pollly ⁇) - piosenka amerykańskiego zespołu rockowego Nirvana, napisana przez wokalista i gitarzystę zespołu Kurt Cobaina.</p>", "Polonia": "Z reguły pojęcie to odnosi się do potomków polskich <a href=\"https://pl.wikipedia.org/wiki/Emigrant\" target=\"_blank\" rel=\"noopener noreferrer\">emigrantów</a> w krajach takich jak <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stany Zjednoczone</a>, <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francja</a> czy <a href=\"https://pl.wikipedia.org/wiki/Brazylia\" target=\"_blank\" rel=\"noopener noreferrer\">Brazylia</a>. W węższym znaczeniu natomiast uwzględnia ono osoby poczuwające się do polskiego pochodzenia i związków z polskością, lecz urodzonych poza Polską; osoby te związki z tradycją i kulturą narodową zachowują w drugim lub w dalszych pokoleniach i na różnym poziomie identyfikowania się z polskimi sprawami.", "Petrova": "<p>Petrova jest gmina w hrabstwie Maramureș, Rumunii. W 2002 roku liczba ludności wynosiła 2710.</p>", "Pollyanna": "<p>⁇ Pollyanna ⁇ (ang. Pollyanna) - romans-bestseller amerykańskiej pisarzy Eleanor Porter, opublikowany w 1913 roku.</p>", "Partycja": "<b>Partycja</b> – wydzielony logiczny obszar <a href=\"https://pl.wikipedia.org/wiki/Dysk_twardy\" target=\"_blank\" rel=\"noopener noreferrer\">dysku twardego</a>, który może być sformatowany przez <a href=\"https://pl.wikipedia.org/wiki/System_operacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">system operacyjny</a> w odpowiednim <a href=\"https://pl.wikipedia.org/wiki/System_plik%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">systemie plików</a>. Niekiedy określenie partycja odnosi się do wydzielonego zasobu innego niż dysk na przykład partycja jako wydzielony logiczny komputer (PR/SM) lub partycjonowanie przełączników Fiber Channel lub ESCON Director.", "Pari": "<p>Pari może odnosić się do: Paris Pari (praca) Pari (czyty)</p>", "Petya": "<p>Petya (znana również jako Petya.A, Petya.D, Trojan.Ransom.Petya, Petya Ransomware, PetrWrap, Petya; podobny wirus - NotPetya, ExPetr, GoldenEye) - złośliwy program, robak sieciowy i program-wyłamanie, które atakują komputery pod sterowaniem Microsoft Windows. Pierwsze odmiany wirusa zostały wykryte w marcu 2016 roku.</p>", "Polyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Polina</b>.</p><b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Phương Anh": "<p>Phương Anh może odnosić się do: Nguyen Phương Anh, wietnamskiego piosenkarza urodzony w 1982 roku. Nguyen Phương anh, urodzony 1997 roku.</p>", "Payal": "<p>Payal jest miastem i miejscem miejscowości (municipal council) w Ludhiana w stanie Punjab w Indiach.</p>", "Patricja": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patrycja</b>.</p><b>Patrycja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskich imion <a href=\"https://pl.wikipedia.org/wiki/Patrycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Patrycy\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycy</a>, <a href=\"https://pl.wikipedia.org/wiki/Patryk\" target=\"_blank\" rel=\"noopener noreferrer\">Patryk</a>. Oznacza „szlachetnie urodzona, patrycjuszowska”. Wśród imion nadawanych nowo narodzonym dzieciom, Patrycja w 2017 r. zajmowała 58. miejsce w grupie imion żeńskich. W całej populacji Polek Patrycja zajmowała w 2017 r. 41. miejsce (166 497 nadań).", "Pamella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pamela</b>.</p><b>Pamela</b> – imię żeńskie pochodzenia literackiego, wymyślone przez <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI-wiecznego</a> poetę <a href=\"https://pl.wikipedia.org/wiki/Philip_Sidney\" target=\"_blank\" rel=\"noopener noreferrer\">Philipa Sidneya</a> na użytek poematu <i>Arkadia</i> w 1590 roku. W 1740 roku <a href=\"https://pl.wikipedia.org/wiki/Samuel_Richardson\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel Richardson</a> uczynił osobę o tym imieniu tytułową bohaterką powieści <i>Pamela, czyli Cnota nagrodzona</i>. Powieść tę sparodiował szybko <a href=\"https://pl.wikipedia.org/wiki/Henry_Fielding\" target=\"_blank\" rel=\"noopener noreferrer\">Henry Fielding</a>, pisząc swój debiut literacki <i><a href=\"https://pl.wikipedia.org/wiki/An_Apology_for_the_Life_of_Mrs._Shamela_Andrews\" target=\"_blank\" rel=\"noopener noreferrer\">An Apology for the Life of Mrs. Shamela Andrews</a></i>, przyczyniając się do upowszechnienia imienia Pamela.", "Phyllis": "<p>Phyllis lub Phillis jest kobiece nazwisko pochodzenia greckiego oznaczające liście. Phyllis jest osobą nieznaczną w mitologii greckiej, która zabiła się w rozpaczy, gdy Demophon z Aten nie wrócił do niej i została przekształcona w migdałowe drzewo przez bogów.</p>", "Portia": "<p>Portia (lat. Portia) - rodzaj pająków z rodziny pająków-skakunów. Ponad 17 gatunków, które żywią się innymi pająkami (tj. są araneofagami lub arachnofagami).</p>", "Parvina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Parvin</b>.</p><p>Parveen (persk: پروین) to perskiej kurdyjskiej nazwy, która oznacza Plejady. Jest powszechnie stosowany w Iranie, Afganistanie, Tadżykistanie, Pakistanie i Indiach.</p>", "Princesa": "<p>Princesa to miasto w Brazylii. Miasto ma powierzchnię 86,215 km2, liczba ludności w 2007 roku wynosi 2604 mieszkańców, a jego gęstość wynosi 27,9 mieszkańców/km2.</p>", "Philomena": "<p>⁇ Philomena ⁇ (ang. Philomena) - film dramatyczny reżysera Stephena Frirza, który ukazał się na ekranach w 2013 roku.</p>", "Praskoviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Praskovia</b>.</p><p>Praskovya lub Praskovia (rosyjski: Прасковья) to starożytna rosyjska imiona żeńska. Pochodzi ona od greckiego imienia parazystego, co oznacza \"przygotowanie\" lub \"piątek\" (piątek jest dniem przygotowania), nazwy męczenników świętego II wieku.</p>", "Poliksena": "Homer nie umieścił jej w Iliadzie. Według poetów cyklicznych Poliksena była branką <a href=\"https://pl.wikipedia.org/wiki/Achilles\" target=\"_blank\" rel=\"noopener noreferrer\">Achillesa</a> i pocieszała go po śmierci <a href=\"https://pl.wikipedia.org/wiki/Patroklos\" target=\"_blank\" rel=\"noopener noreferrer\">Patroklosa</a>. Achilles towarzyszył Poliksenie do świątyni, wtedy wpadł w pułapkę braci Polikseny – <a href=\"https://pl.wikipedia.org/wiki/Deifobos\" target=\"_blank\" rel=\"noopener noreferrer\">Deifobosa</a> i <a href=\"https://pl.wikipedia.org/wiki/Parys\" target=\"_blank\" rel=\"noopener noreferrer\">Parysa</a> – i został zabity. Poliksena z żalu popełniła samobójstwo lub też syn Achillesa, <a href=\"https://pl.wikipedia.org/wiki/Neoptolemos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Neoptolemos</a>, zabił ją po zdobyciu Troi na grobie swego ojca jako ofiarę. Stąd wywodzi się opowieść o miłości Achillesa do Polikseny. Mit stał się kanwą utworów antycznych (<a href=\"https://pl.wikipedia.org/wiki/Sofokles\" target=\"_blank\" rel=\"noopener noreferrer\">Sofokles</a>, <a href=\"https://pl.wikipedia.org/wiki/Eurypides\" target=\"_blank\" rel=\"noopener noreferrer\">Eurypides</a>) i nowożytnych. Czasem Poliksenę nazywa się <i>trojańską <a href=\"https://pl.wikipedia.org/wiki/Ifigenia\" target=\"_blank\" rel=\"noopener noreferrer\">Ifigenią</a></i>.", "Pratiksha": "<p>Pratiksha (przekładając; Nepali: प्रतीक्षा) to żeńskie imię w językach hindi i nepali.</p>", "Piper": "<p>Piper: Piper (lat.) - nazwa naukowa gatunku roślin Perczaków rodziny Perczak (Piperaceae); Piper - skrócenie botaniczne, oznaczające, że autorem taksyny jest Piper, Charles Vancouver. Piper Aircraft - firma lotnicza; Piper PA-46 - samolot.</p>", "Praskovia": "<p>Praskovya lub Praskovia (rosyjski: Прасковья) to starożytna rosyjska imiona żeńska. Pochodzi ona od greckiego imienia parazystego, co oznacza \"przygotowanie\" lub \"piątek\" (piątek jest dniem przygotowania), nazwy męczenników świętego II wieku.</p>", "Pauliina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pauli</b>.</p><p>Pauli to nazwisko i także fińskie męskie nazwisko (variant Paul) i może odnosić się do:</p>", "Przybysława": "<b>Przybysława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Przyby-</i> (\"przybyć, przybywać\") oraz <i>-sława</i> (\"sława\"). Mogło oznaczać \"ta, która przynosi sławę\". W źródłach poświadczone w XII wieku (1168 rok).", "Phương Thảo": "<p>Phan Thảo może być: Phạm Phạm Thảo, Wicek Sekretarz Członkowski, Przewodniczący Rady Ludowej Miasta Ho Chi Minh City (2004-2011) Phạm Phương Thảo, piosenkarz, Artysta Elit, Nagroda 3 Ludowej Muzyki Ludowej w Sao Mai 2003. Singer Tanh Tảo, prawdziwa nazwa jest Phan Phan Phong Tảo Singer Phong Tào, prawdziwa jest Van Thi Kim Lang, żona piosenkarki - muzyki Ngọc Lễ.</p>", "Prerna": "<p>Prerna lub Prerana to słowo hindusko-sanskritskie, które pochodzi od słowa \"Prernah\". Jego tłumaczenie jest natchnieniem.</p>", "Pryscylla": "<b>Pryska</b>, <b>Pryscylla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskich</a> imion Prisca, Priscilla (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>priscus</em> – „starodawny; surowy, poważny”). W Polsce rzadko spotykane, choć zapisano je już w XV&#160;wieku. Jego patronką jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Pryska\" target=\"_blank\" rel=\"noopener noreferrer\">Pryska</a>, męczennica.", "Pesia": "<p>Pesya lub Pesia (rosyjski: Песя) to wschodnie aszkenazyjskie imię kobiety, diminutiw Pauliny lub Poliny. Wystarczy, że w przypadku dzieci jest to hipokorystyczna forma.</p>", "Paradise": "<p>Paradise (z angielskiego - ⁇ рай ⁇) może oznaczać następujące: Paradise - album Cody Simpson.</p>", "Prascovia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Praskovia</b>.</p><p>Praskovya lub Praskovia (rosyjski: Прасковья) to starożytna rosyjska imiona żeńska. Pochodzi ona od greckiego imienia parazystego, co oznacza \"przygotowanie\" lub \"piątek\" (piątek jest dniem przygotowania), nazwy męczenników świętego II wieku.</p>", "Piotra": "<b>Piotra</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Piotr_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Piotr</a>, chrześcijańskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywiedzionego od przydomku <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a> apostoła nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a> <i>Kefas</i>). Imię Piotr (Πέτρος) jest czasami tłumaczone jako „Skała”, co w języku polskim oznacza z reguły wielki kamienny masyw. Polska forma <i>Pi<b>o</b>tr</i> z <i>„o”</i> zamiast <i>„e”</i> jest regularną zmianą spowodowaną przez <a href=\"https://pl.wikipedia.org/wiki/Przeg%C5%82os_lechicki\" target=\"_blank\" rel=\"noopener noreferrer\">przegłos lechicki</a> (por. też np. <i>kości<b>ó</b>ł</i> z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>cast<b>e</b>l</i>.)", "Pavithra": "<p>Pavithra może odnosić się do: Pavithra (film) 1994 Indian Tamil-języczny film dramatyczny Pavithra Lakshmi, indyjska aktorka Pavitra Lokesh, indyjskiej aktorki filmowej i telewizyjnej Pavithra Janani, indyjski aktorka telewizyjna Pavithra Vengatesh, indyjskiego sportowca Pavithra Wanniarachchi, Sri Lankanki prawnik i polityk</p>", "Pranavi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pranav</b>.</p><p>Pranav (sanskrit: प्रणव, romanized: Praṇava) to indyjskie imię męskie oznaczające Om, święty dźwięk i symbol. Według hinduizmu pranawa jest zdaniem siłą Brahmę, Wisnu i Shiwy łączonej.</p>", "Päivi": "<p>Päivi to fińskie imię dla kobiet, pochodzące od słowa \"päivä\", co oznacza \"dzień\". Jego dzień nazwy jest 16 czerwca.</p>", "Pryska": "<b>Pryska</b>, <b>Pryscylla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskich</a> imion Prisca, Priscilla (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>priscus</em> – „starodawny; surowy, poważny”). W Polsce rzadko spotykane, choć zapisano je już w XV&#160;wieku. Jego patronką jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Pryska\" target=\"_blank\" rel=\"noopener noreferrer\">Pryska</a>, męczennica.", "Plamena": "<b>Płamena</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a> <i>Пламенa</i>) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskiego</a> męskiego imienia <i><a href=\"https://pl.wikipedia.org/wiki/P%C5%82amen\" target=\"_blank\" rel=\"noopener noreferrer\">Płamen</a></i>, którego znaczenie odnosi się do <a href=\"https://pl.wikipedia.org/wiki/P%C5%82omie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">płomienia</a>.", "Pernille": "<p>Pernille to duńskie i norweskie nazwisko pochodzące od Petronella i może odnosić się do: Pernille Agerholm (ur. 1991), duńska tenista tabeli Pernille Christensen (ur. 1974), duńska politykka Pernille Dupont, emeryturka badmintonistka z Danii Pernille Fischer Christensen (ura. 1969), duńskie reżyser filmowy i siostra aktora Stine Fischer Christensena Pernille Harder (ur. 1977), badmintonista z...</p>", "Pulcheria": "<b>Pulcheria</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"piękna\", \"szlachetna\".", "Paschalina": "<b>Paschalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Paschalis\" target=\"_blank\" rel=\"noopener noreferrer\">Paschalis</a>. Wywodzi się od słowa „pascha” oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Wielkanoc\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkanoc</a>. W swych korzeniach sięga <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>pesah</i> oznaczającego żydowskie święto wyjścia, upamiętniające opuszczenie <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egiptu</a> i początek drogi do <a href=\"https://pl.wikipedia.org/wiki/Ziemia_Obiecana_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi Obiecanej</a>.", "Parvati": "<b>Parwati</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> <b>पार्वती</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tamilski\" target=\"_blank\" rel=\"noopener noreferrer\">tamilski</a>: <b>பார்வதி</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> Parvati) – <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> hinduistyczna reprezentująca łagodny aspekt <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aakti\" target=\"_blank\" rel=\"noopener noreferrer\">Śakti</a>, mocy boga <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>. Początkowo odrębna od innych plemiennych bogiń, w późniejszym <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> stopniowo przejmując niektóre ich atrybuty, często jest z nimi utożsamiana. Z biegiem czasu stała się uogólnioną personifikacją kobiecości, <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>, zwłaszcza w jej matczynym aspekcie jako Matadźi, czyli <a href=\"https://pl.wikipedia.org/wiki/Bogini_Matka\" target=\"_blank\" rel=\"noopener noreferrer\">Bogini Matka</a>. Często bywa łączona z <a href=\"https://pl.wikipedia.org/wiki/Saraswati\" target=\"_blank\" rel=\"noopener noreferrer\">Saraswati</a> i <a href=\"https://pl.wikipedia.org/wiki/Lakszmi\" target=\"_blank\" rel=\"noopener noreferrer\">Lakszmi</a> w trójcę bogiń, nazywaną <a href=\"https://pl.wikipedia.org/wiki/Tridewi\" target=\"_blank\" rel=\"noopener noreferrer\">Tridewi</a>. Bywa nazywana imieniem Arja.", "Paula Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Priska": "<p>Priska może odnosić się do: Priska Doppmann (ur. 1971), szwajcarka rowerka wyścigowa na drogach Priska Nufer (ur. 1992), szwajcarska wyścigowka na nartach górskich Priska Madelyn Nugroho (ur. 2003), indonezyjska tenisa Priska Polačeková (ur. 1954), były czechosłowacka / słowacka piłkarka ręczna 997 Priska, asteroida z głównego pasu</p>", "Pavlova": "Nazwa pochodzi od nazwiska rosyjskiej <a href=\"https://pl.wikipedia.org/wiki/Primabalerina\" target=\"_blank\" rel=\"noopener noreferrer\">primabaleriny</a> <a href=\"https://pl.wikipedia.org/wiki/Anna_Paw%C5%82owa\" target=\"_blank\" rel=\"noopener noreferrer\">Anny Pawłowej</a> – tradycja głosi, że pierwszy raz został przygotowany podczas pobytu <a href=\"https://pl.wikipedia.org/wiki/Taniec_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">tancerki</a> w <a href=\"https://pl.wikipedia.org/wiki/Perth\" target=\"_blank\" rel=\"noopener noreferrer\">Perth</a> w 1926 lub 1929 roku przez szefa kuchni hotelu Esplanade. Jednak do autorstwa deseru pretendują także <a href=\"https://pl.wikipedia.org/wiki/Nowa_Zelandia\" target=\"_blank\" rel=\"noopener noreferrer\">Nowozelandczycy</a>, twierdząc, że przyrządzono go w <a href=\"https://pl.wikipedia.org/wiki/Wellington\" target=\"_blank\" rel=\"noopener noreferrer\">Wellington</a> podczas <a href=\"https://pl.wikipedia.org/wiki/Trasa_koncertowa\" target=\"_blank\" rel=\"noopener noreferrer\">tournée</a> Pawłowej w <a href=\"https://pl.wikipedia.org/wiki/1926\" target=\"_blank\" rel=\"noopener noreferrer\">1926</a> roku.", "Phatima": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fatima</b>.</p><b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Petrovna": "<p>Peter to powszechne męskie imię. Pochodzi bezpośrednio z greckiego Πέτρος, Petros (wynaleziona, męska forma greckiego petra, słowo dla \" skały \"lub \"kamień\"), które samo w sobie było tłumaczeniem aramejskiego Kefa (\"kamień, skała\"), nowa nazwa, którą Jezus dał apostołowi Simon bar Jona.</p>", "Pei-Hsuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Parysa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Parys</b>.</p>Na kilka dni przed porodem jego matka miała sen, że „wydała na świat żagiew płonącą, od której spłonęło całe miasto”. Wróżbici przepowiedzieli, że dziecko będzie przyczyną upadku <a href=\"https://pl.wikipedia.org/wiki/Troja\" target=\"_blank\" rel=\"noopener noreferrer\">Troi</a>. Zostało więc oddane pasterzowi Agelaosowi, aby ten porzucił chłopca w górach. Agelaos jednak nadał chłopcu imię Parys i wychował razem ze swoimi dziećmi. Gdy Parys dorósł, Priam i Hekabe, nie wiedząc nic o królewskim pochodzeniu młodzieńca, przyjęli go do swego domu i ożenili z <a href=\"https://pl.wikipedia.org/wiki/Ojnone\" target=\"_blank\" rel=\"noopener noreferrer\">Ojnone</a>. Rozpoznał go dopiero jego brat, <a href=\"https://pl.wikipedia.org/wiki/Deifobos\" target=\"_blank\" rel=\"noopener noreferrer\">Deifobos</a>.", "Przemiła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Przemił</b>.</p><b>Przemił</b>, <b>Przemieł</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Prze-</i> (\"przez\" i wiele innych znaczeń) i <i>-mił</i>, <i>-mieł</i> (\"miły\"). Być może oznaczało \"najmilszy\".", "Pollianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pollyanna</b>.</p><p>⁇ Pollyanna ⁇ (ang. Pollyanna) - romans-bestseller amerykańskiej pisarzy Eleanor Porter, opublikowany w 1913 roku.</p>", "Piotryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Piotr</b>.</p><b>Piotr</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przydomku apostoła <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Szymona</a>, nadanego mu przez <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Πέτρος (<i>petros</i>) – „kamień, głaz”, przejęte jako <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Petrus</em> i do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> bezpośrednio z łaciny. W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> wymieniane w wersetach <a href=\"https://biblia.deon.pl/otworz.php?skrot=Mt%2016,18\" target=\"_blank\" rel=\"noopener noreferrer\">Mt 16,18</a> i J 1,42. Jest to jedno z <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najwcześniej notowanych w Polsce imion</a>, po raz pierwszy zapisane w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku, w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Polla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pola</b>.</p><b>Pola</b> – zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolonia\" target=\"_blank\" rel=\"noopener noreferrer\">Apolonia</a>. Zaczęło być nadawane jako samodzielne imię. Być może usamodzielniła się pod wpływem pomieszania zdrobnienia Apolonii z imieniem <a href=\"https://pl.wikipedia.org/wiki/Paula\" target=\"_blank\" rel=\"noopener noreferrer\">Paula</a>, wymawianym w niektórych językach jako Pola. Wśród imion nadawanych nowo narodzonym dzieciom, Pola zajmuje 11. miejsce w grupie imion żeńskich.", "Pera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Per</b>.</p><p>Per: per - łaciński pretekst, odpowiadający słowom ⁇ ceрез ⁇ , ⁇ skvoзь ⁇ , ??po ⁇ lub ⁇ wzdłuż ⁇; część oznaczeń naukowych (np. per capita) i krytycznych fraz (np., per aspera ad astra). PeR - lotyjski pop-grupowy, założony w 2007 roku.</p>", "Poziomka": "<b>Poziomka</b> (<i>Fragaria</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Bylina_(botanika)\" target=\"_blank\" rel=\"noopener noreferrer\">bylin</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCowate\" target=\"_blank\" rel=\"noopener noreferrer\">różowatych</a>. Obejmuje 22 gatunki. Rośliny te występują na półkuli północnej i w <a href=\"https://pl.wikipedia.org/wiki/Chile\" target=\"_blank\" rel=\"noopener noreferrer\">Chile</a>. W Polsce rosną w naturze trzy gatunki, poza tym podobnie jak w wielu innych krajach, rozpowszechniony jest w uprawie mieszaniec międzygatunkowy – <a href=\"https://pl.wikipedia.org/wiki/Truskawka\" target=\"_blank\" rel=\"noopener noreferrer\">truskawka</a> (<i>Fragaria ×ananassa</i>). Ten takson o istotnym znaczeniu ekonomicznym powstał w wyniku skrzyżowania poziomki chilijskiej i wirginijskiej. W naturze poziomki zasiedlają zazwyczaj słoneczne murawy, obrzeża lasów i lasy świetliste.", "Paria": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pari</b>.</p><p>Pari może odnosić się do: Paris Pari (praca) Pari (czyty)</p>", "Paivi": "<p>Päivi to fińskie imię dla kobiet, pochodzące od słowa \"päivä\", co oznacza \"dzień\". Jego dzień nazwy jest 16 czerwca.</p>", "Papusza": "<b>Papusza</b>, właśc. <b>Bronisława Wajs</b> (<b>Wajss</b>) z domu Zielińska (ur. <a href=\"https://pl.wikipedia.org/wiki/17_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">17 sierpnia</a> <a href=\"https://pl.wikipedia.org/wiki/1908\" target=\"_blank\" rel=\"noopener noreferrer\">1908</a> w <a href=\"https://pl.wikipedia.org/wiki/Sitaniec\" target=\"_blank\" rel=\"noopener noreferrer\">Sitańcu</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/8_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">8 lutego</a> <a href=\"https://pl.wikipedia.org/wiki/1987\" target=\"_blank\" rel=\"noopener noreferrer\">1987</a> w <a href=\"https://pl.wikipedia.org/wiki/Inowroc%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Inowrocławiu</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">polska</a> <a href=\"https://pl.wikipedia.org/wiki/Poezja\" target=\"_blank\" rel=\"noopener noreferrer\">poetka</a> wywodząca się z <a href=\"https://pl.wikipedia.org/wiki/Romowie_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">romskiej</a> grupy etnicznej <a href=\"https://pl.wikipedia.org/wiki/Polska_Roma\" target=\"_blank\" rel=\"noopener noreferrer\">Polska Roma</a>, pisząca w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_romski\" target=\"_blank\" rel=\"noopener noreferrer\">języku romskim</a>.", "Prerana": "<p>Prerna lub Prerana to słowo hindusko-sanskritskie, które pochodzi od słowa \"Prernah\". Jego tłumaczenie jest natchnieniem.</p>", "Pilar Del Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pilar</b>.</p><p>Pilar to miasto w Brazylii. Miasto to ma powierzchnię 248,98 km2, liczba ludności w 2007 roku wynosi 30652 osób, a jego gęstość 123,11 osób/km2.</p>", "Pauletta": "<b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Phebe": "<p>Phebe to kobiece imię związane z Phoebe. Może odnosić się do: Phebe Bekker (ur. 2005), brytyjskiej tancerki lodowej Phebe Gibbes (ur. 1805), angielskiej pisarzy i wczesnej feministki Phebe Ann Coffin Hanaford (1829-1921), chrześcijańskiego uniwersalistycznego ministra, biografa i aktywisty dla ogólnego wyboru i praw kobiet Phebe Hayes, amerykańskiej niezależnej historykę z Iberia Parish, Louisiana; były profesor patologii mowy Phebe Hemphill (ur. ...</p>", "Pornthip": "<p>Porntip lub Pornthip to tajskie nazwisko dla kobiet. To samo wymowę dzielą dwa różne pisowni, พรทิพย์ i ภรณ์ทิพย์.</p>", "Philadelphia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Filadelfia</b>.</p><b>Filadelfia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <i>φιλεω (fileo)</i> - \"kochać\" i <i>αδελφος (adelfos)</i> - \"brat\", co oznaczało \"braterska miłość\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Filadelf\" target=\"_blank\" rel=\"noopener noreferrer\">Filadelf</a>, wspominany razem ze swoimi braćmi, św. Alfiuszem i <a href=\"https://pl.wikipedia.org/wiki/Cyryn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrynem</a> (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Paula Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Pradeepa": "<p>Pradeepa to imię. Znani ludzie z nazwiskiem to: Pradeepa Dharmadasa (ur. 1964), śrilankański muzyk Pradeepa Herath (ur. 1976), Sri Lankański były sprinter</p>", "Poranek": "<b>Poranek</b>, także <b>ranek</b> lub <b>rano</b> – dający się obiektywnie wyróżnić moment w ciągu <a href=\"https://pl.wikipedia.org/wiki/Doba\" target=\"_blank\" rel=\"noopener noreferrer\">doby</a> jako wczesna część <a href=\"https://pl.wikipedia.org/wiki/Dzie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dnia</a> (pora dnia), mająca miejsce około <a href=\"https://pl.wikipedia.org/wiki/Wsch%C3%B3d_S%C5%82o%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">wschodu słońca</a> i trwająca do <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udnie_(12:00)\" target=\"_blank\" rel=\"noopener noreferrer\">południa</a>; <a href=\"https://pl.wikipedia.org/wiki/Okolicznik\" target=\"_blank\" rel=\"noopener noreferrer\">Okolicznik</a> czasu definiujący początek dnia – czas gdy zaczyna się aktywność <a href=\"https://pl.wikipedia.org/wiki/S%C5%82o%C5%84ce\" target=\"_blank\" rel=\"noopener noreferrer\">Słońca</a>. Określenie służące do odmierzania przybliżonego czasu, wywodzące się z okresu w dziejach ludzkości gdy czas określany był na podstawie ruchu słońca. Jako początek poranka spotyka się definicje wiążącą go z bezpośrednim okresem po przebudzeniu osoby bardziej niż aktywnością słońca. Ten typ postrzegania poranka pojawił się wraz z pojawieniem się sztucznego oświetlenia i towarzyszącą mu niezależnością od naturalnego światła.", "Paula Fernanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Pei-Lin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Praskoviya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Praskovia</b>.</p><p>Praskovya lub Praskovia (rosyjski: Прасковья) to starożytna rosyjska imiona żeńska. Pochodzi ona od greckiego imienia parazystego, co oznacza \"przygotowanie\" lub \"piątek\" (piątek jest dniem przygotowania), nazwy męczenników świętego II wieku.</p>", "Pawłowa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pavlova</b>.</p>Nazwa pochodzi od nazwiska rosyjskiej <a href=\"https://pl.wikipedia.org/wiki/Primabalerina\" target=\"_blank\" rel=\"noopener noreferrer\">primabaleriny</a> <a href=\"https://pl.wikipedia.org/wiki/Anna_Paw%C5%82owa\" target=\"_blank\" rel=\"noopener noreferrer\">Anny Pawłowej</a> – tradycja głosi, że pierwszy raz został przygotowany podczas pobytu <a href=\"https://pl.wikipedia.org/wiki/Taniec_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">tancerki</a> w <a href=\"https://pl.wikipedia.org/wiki/Perth\" target=\"_blank\" rel=\"noopener noreferrer\">Perth</a> w 1926 lub 1929 roku przez szefa kuchni hotelu Esplanade. Jednak do autorstwa deseru pretendują także <a href=\"https://pl.wikipedia.org/wiki/Nowa_Zelandia\" target=\"_blank\" rel=\"noopener noreferrer\">Nowozelandczycy</a>, twierdząc, że przyrządzono go w <a href=\"https://pl.wikipedia.org/wiki/Wellington\" target=\"_blank\" rel=\"noopener noreferrer\">Wellington</a> podczas <a href=\"https://pl.wikipedia.org/wiki/Trasa_koncertowa\" target=\"_blank\" rel=\"noopener noreferrer\">tournée</a> Pawłowej w <a href=\"https://pl.wikipedia.org/wiki/1926\" target=\"_blank\" rel=\"noopener noreferrer\">1926</a> roku.", "Padmaja": "<p>Padmaja może odnosić się do Padmaja, epitetu hinduistycznej bogini Lakshmi Padmaja Naidu, byłego gubernatora Bengali Zachodniej, India PadmajaNaidu Himalayan Zoological Park, park znajdujący się w Darjeeling, Bengal Zachodnie, India Padmja Phenany Joglekar, Hindustani klasyczny piosenkarz Padmaja Rao, indyjska aktorka, dyrektor telewizyjny i producent</p>", "Pei-Ying": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Paula Marcela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Pryma": "<b>Pryma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe od liczebnika <i>prima</i> – \"pierwsza\". Patronem tego imienia jest św. Pryma, <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennicy_z_Abiteny\" target=\"_blank\" rel=\"noopener noreferrer\">męczennica z Abiteny</a>.", "Pelina": "<b>Pelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pelin\" target=\"_blank\" rel=\"noopener noreferrer\">Pelin</a>. Jego patronem jest św. Pelin, zm. w 361 r., pod rządami <a href=\"https://pl.wikipedia.org/wiki/Julian_Apostata\" target=\"_blank\" rel=\"noopener noreferrer\">Juliana Apostaty</a>.", "Polina-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Polina</b>.</p><b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Przeborka": "<b>Przeborka</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Prze-</i> (\"przez\" i wiele innych znaczeń) i <i>-bor-ka</i> (\"walczyć, zmagać się\"). Być może oznaczało \"tę, która najlepiej walczy\".", "Pudencjanna": "<b>Pudencjanna</b>, <b>Pudencjana</b> — imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „wyzwolona i adoptowana przez Pudencjusza”; Pudencjusz zaś to wtórny <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> pochodzący od innego przydomka, Pudens, używanego w rodzie <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Klaudiuszów</a>, a oznaczającego „skromny, obyczajny”. Patronką imienia w Kościele katolickim jest św. Pudencjana (nazywana zamiennie <a href=\"https://pl.wikipedia.org/wiki/Potencjana\" target=\"_blank\" rel=\"noopener noreferrer\">Potencjaną</a>).", "Palesa": "<p>Palesa to kobiece imię, które oznacza \" kwiat\". Wśród znanych osób z tej nazwy są: Beverley Palesa Ditsie (ur. 1971), południowoafrykańska aktywistka lesbianka, artysta i filmowiec Palesa Madisakwane, południo Afrykańska aktorka Palesa Jacqui Mofokeng (ur. 1972), połudnoafrykajska królowa piękności (Miss Południowa Afryka 1993) Palesa Mokubung, połudnoafrykańska projektantka mody Palesa Molefe, królowa piosenki Motswana (Miss Botswana 2021)</p>", "Pi": "<b>&#960;</b> (czyt. <i>pi</i>), <b>ludolfina</b>, <b>stała Archimedesa</b> – <a href=\"https://pl.wikipedia.org/wiki/Stosunek_(matematyka)\" target=\"_blank\" rel=\"noopener noreferrer\">stosunek</a> <a href=\"https://pl.wikipedia.org/wiki/Obw%C3%B3d_(geometria)\" target=\"_blank\" rel=\"noopener noreferrer\">obwodu</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">koła</a> (czyli <a href=\"https://pl.wikipedia.org/wiki/D%C5%82ugo%C5%9B%C4%87_krzywej\" target=\"_blank\" rel=\"noopener noreferrer\">długości</a> <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%85g\" target=\"_blank\" rel=\"noopener noreferrer\">okręgu</a>) do długości jego <a href=\"https://pl.wikipedia.org/wiki/%C5%9Arednica\" target=\"_blank\" rel=\"noopener noreferrer\">średnicy</a>; stosunek ten jest niezależny od wielkości koła, bowiem wszystkie koła są do siebie <a href=\"https://pl.wikipedia.org/wiki/Podobie%C5%84stwo_(przekszta%C5%82cenie_geometryczne)\" target=\"_blank\" rel=\"noopener noreferrer\">podobne</a>. Liczba &#960; nazywana jest czasami <i>stałą Archimedesa</i> w uznaniu zasług <a href=\"https://pl.wikipedia.org/wiki/Archimedes\" target=\"_blank\" rel=\"noopener noreferrer\">Archimedesa z Syrakuz</a>, który jako pierwszy badał własności i znaczenie w matematyce tej liczby; określenie <i>ludolfina</i> pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ludolph_van_Ceulen\" target=\"_blank\" rel=\"noopener noreferrer\">Ludolpha van Ceulena</a>, który zyskał sławę, przedstawiając tę liczbę z dokładnością do 35 miejsc po przecinku. Grecy nie używali symbolu &#960; – wprowadził go dopiero <a href=\"https://pl.wikipedia.org/wiki/William_Jones_(matematyk)\" target=\"_blank\" rel=\"noopener noreferrer\">William Jones</a>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/Leonhard_Euler\" target=\"_blank\" rel=\"noopener noreferrer\">Leonhard Euler</a>.", "Pola Quinn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pola</b>.</p><b>Pola</b> – zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolonia\" target=\"_blank\" rel=\"noopener noreferrer\">Apolonia</a>. Zaczęło być nadawane jako samodzielne imię. Być może usamodzielniła się pod wpływem pomieszania zdrobnienia Apolonii z imieniem <a href=\"https://pl.wikipedia.org/wiki/Paula\" target=\"_blank\" rel=\"noopener noreferrer\">Paula</a>, wymawianym w niektórych językach jako Pola. Wśród imion nadawanych nowo narodzonym dzieciom, Pola zajmuje 11. miejsce w grupie imion żeńskich.", "Paula-Mihaela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Paula Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Pelagiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pelagia</b>.</p><b>Pelagia</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, pochodzące od przymiotnika <i>pelagios</i>, oznaczającego „morski”. Męskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Pelagiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagiusz</a>.", "Pelagia Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pelagia</b>.</p><b>Pelagia</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, pochodzące od przymiotnika <i>pelagios</i>, oznaczającego „morski”. Męskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Pelagiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagiusz</a>.", "Pii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pi</b>.</p><b>&#960;</b> (czyt. <i>pi</i>), <b>ludolfina</b>, <b>stała Archimedesa</b> – <a href=\"https://pl.wikipedia.org/wiki/Stosunek_(matematyka)\" target=\"_blank\" rel=\"noopener noreferrer\">stosunek</a> <a href=\"https://pl.wikipedia.org/wiki/Obw%C3%B3d_(geometria)\" target=\"_blank\" rel=\"noopener noreferrer\">obwodu</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">koła</a> (czyli <a href=\"https://pl.wikipedia.org/wiki/D%C5%82ugo%C5%9B%C4%87_krzywej\" target=\"_blank\" rel=\"noopener noreferrer\">długości</a> <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%85g\" target=\"_blank\" rel=\"noopener noreferrer\">okręgu</a>) do długości jego <a href=\"https://pl.wikipedia.org/wiki/%C5%9Arednica\" target=\"_blank\" rel=\"noopener noreferrer\">średnicy</a>; stosunek ten jest niezależny od wielkości koła, bowiem wszystkie koła są do siebie <a href=\"https://pl.wikipedia.org/wiki/Podobie%C5%84stwo_(przekszta%C5%82cenie_geometryczne)\" target=\"_blank\" rel=\"noopener noreferrer\">podobne</a>. Liczba &#960; nazywana jest czasami <i>stałą Archimedesa</i> w uznaniu zasług <a href=\"https://pl.wikipedia.org/wiki/Archimedes\" target=\"_blank\" rel=\"noopener noreferrer\">Archimedesa z Syrakuz</a>, który jako pierwszy badał własności i znaczenie w matematyce tej liczby; określenie <i>ludolfina</i> pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ludolph_van_Ceulen\" target=\"_blank\" rel=\"noopener noreferrer\">Ludolpha van Ceulena</a>, który zyskał sławę, przedstawiając tę liczbę z dokładnością do 35 miejsc po przecinku. Grecy nie używali symbolu &#960; – wprowadził go dopiero <a href=\"https://pl.wikipedia.org/wiki/William_Jones_(matematyk)\" target=\"_blank\" rel=\"noopener noreferrer\">William Jones</a>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/Leonhard_Euler\" target=\"_blank\" rel=\"noopener noreferrer\">Leonhard Euler</a>.", "Pei-Chun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Pin": "Określenie <b>pin</b> (ale już nie nóżka) jest również używane przy nazywaniu kolejnych styków w <a href=\"https://pl.wikipedia.org/wiki/Interfejs_(urz%C4%85dzenie)\" target=\"_blank\" rel=\"noopener noreferrer\">interfejsach</a> komputerowych (np. <a href=\"https://pl.wikipedia.org/wiki/RS-232\" target=\"_blank\" rel=\"noopener noreferrer\">RS-232</a> lub <a href=\"https://pl.wikipedia.org/wiki/IEEE_1284\" target=\"_blank\" rel=\"noopener noreferrer\">Centronics</a>) lub ogólniej w <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82%C4%85cze_(elektronika)\" target=\"_blank\" rel=\"noopener noreferrer\">złączach elektronicznych</a>. W takim przypadku nazwa <b>pin</b> oznacza małe szpilkowe bolce umieszczone we <a href=\"https://pl.wikipedia.org/wiki/Wtyczka_(elektronika)\" target=\"_blank\" rel=\"noopener noreferrer\">wtyczkach</a> (zob. zdjęcie obok) lub w <a href=\"https://pl.wikipedia.org/wiki/Gniazdo_(elektronika)\" target=\"_blank\" rel=\"noopener noreferrer\">gniazdach</a> złączy elektronicznych.", "Patricia-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Patricia</b>.</p><p>Patricia może odnosić się do: Patricia Rodriguez 436 Patricia</p>", "Pelagiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pelagia</b>.</p><b>Pelagia</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, pochodzące od przymiotnika <i>pelagios</i>, oznaczającego „morski”. Męskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Pelagiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagiusz</a>.", "Pixie": "<b>Pixie</b> (również <b>Pixy</b>, <b>Pixi</b>, w <a href=\"https://pl.wikipedia.org/wiki/Kornwalia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornwalii</a> – <b>pigsie</b>) – w brytyjskim <a href=\"https://pl.wikipedia.org/wiki/Folklor\" target=\"_blank\" rel=\"noopener noreferrer\">folklorze</a> małe postaci obdarzone magiczną mocą zamieszkałe głównie na południu <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">Anglii</a>, w <a href=\"https://pl.wikipedia.org/wiki/Devon\" target=\"_blank\" rel=\"noopener noreferrer\">Devonie</a> i Kornwalii, co sugeruje ich celtyckie pochodzenie i nazwę. W opisach z <a href=\"https://pl.wikipedia.org/wiki/Epoka_wiktoria%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">epoki wiktoriańskiej</a> zwykle pojawiają się ze spiczastymi uszami, w zielonym stroju i spiczastym kapeluszu. W niektórych opisach oczy mają zwrócone ku górze. We współczesnym użyciu wyraz <i>pixie</i> jest bliskoznaczny z pojęciem <a href=\"https://pl.wikipedia.org/wiki/Wr%C3%B3%C5%BCka_(literatura)\" target=\"_blank\" rel=\"noopener noreferrer\">wróżki</a>, jednak w folklorze rasy te były ze sobą skłócone. Najbliższym polskim odpowiednikiem oryginalnego znaczenia będzie <a href=\"https://pl.wikipedia.org/wiki/Krasnoludek\" target=\"_blank\" rel=\"noopener noreferrer\">krasnoludek</a>.", "Praskowia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Praskovia</b>.</p><p>Praskovya lub Praskovia (rosyjski: Прасковья) to starożytna rosyjska imiona żeńska. Pochodzi ona od greckiego imienia parazystego, co oznacza \"przygotowanie\" lub \"piątek\" (piątek jest dniem przygotowania), nazwy męczenników świętego II wieku.</p>", "Pin-Hsuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pin</b>.</p>Określenie <b>pin</b> (ale już nie nóżka) jest również używane przy nazywaniu kolejnych styków w <a href=\"https://pl.wikipedia.org/wiki/Interfejs_(urz%C4%85dzenie)\" target=\"_blank\" rel=\"noopener noreferrer\">interfejsach</a> komputerowych (np. <a href=\"https://pl.wikipedia.org/wiki/RS-232\" target=\"_blank\" rel=\"noopener noreferrer\">RS-232</a> lub <a href=\"https://pl.wikipedia.org/wiki/IEEE_1284\" target=\"_blank\" rel=\"noopener noreferrer\">Centronics</a>) lub ogólniej w <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82%C4%85cze_(elektronika)\" target=\"_blank\" rel=\"noopener noreferrer\">złączach elektronicznych</a>. W takim przypadku nazwa <b>pin</b> oznacza małe szpilkowe bolce umieszczone we <a href=\"https://pl.wikipedia.org/wiki/Wtyczka_(elektronika)\" target=\"_blank\" rel=\"noopener noreferrer\">wtyczkach</a> (zob. zdjęcie obok) lub w <a href=\"https://pl.wikipedia.org/wiki/Gniazdo_(elektronika)\" target=\"_blank\" rel=\"noopener noreferrer\">gniazdach</a> złączy elektronicznych.", "Paula Camila": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Patrycija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patrycia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patricia</b>.</p><p>Patricia może odnosić się do: Patricia Rodriguez 436 Patricia</p>", "Panpan": "Nazywano je także „Pansuke” (パン助), „Panpangāru” (パンパンガール), „Yoru no Onna” (夜の女 dosł. kobieta nocy), „Yami no Onna” (闇の女 dosł. kobieta ciemności). Termin „Yami no Onna” (闇の女 dosł. kobieta ciemności) był używany w tym samym czasie w odniesieniu do prostytutek ulicznych wraz z japońskimi odpowiednikami, ale z czasem to rozróżnienie zniknęło.", "Pija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pia</b>.</p>Zostało ono utworzone jako żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Pius</a>, którego pierwotne znaczenie to „pobożny, uczciwy, oddany”.", "Patrycya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Patrycy</b>.</p><b>Patrycy</b> jest to oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Patryk\" target=\"_blank\" rel=\"noopener noreferrer\">Patryk</a> i <a href=\"https://pl.wikipedia.org/wiki/Patrycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Patrycjusz</a>.", "Polikarpa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Polikarp</b>.</p><b>Polikarp</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>polykarpos</i> oznaczającego „płodny”.", "Pratika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pratik</b>.</p><p>Pratik lub Prateik to indyjska męska nazwa, która może odnosić się do Prateika Babbar (ur. 1986), indyjskiego aktora Pratik Chaudhari (ur. 1989), indyskiego piłkarza Pratik Desai (ur. 1989, indyjski kryker Pratik Gandhi, indyjski aktor teatralny i filmowy Prateik Jain (ur. 1989.), indyjski model i aktor Pratik Prakashbapu Patil (ur. 1973), indyjscy polityk Pratik A. Shah, amerykański prawnik Pratik Salunke (ur. 1991), indyjska krykerka Pratik...</p>", "Penina": "<p>Pnina (Hebrajskie: פְּנִינָּה lub פְּנוִנָּּה) jest żydowska kobieca nazwa, co oznacza \"perlu\" w języku hebrajskim. Do innych literatury należą Penina, Penina i Penina.</p>", "Patricia Del Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Patricia</b>.</p><p>Patricia może odnosić się do: Patricia Rodriguez 436 Patricia</p>", "Pryncessa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Princessa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Princess</b>.</p><p>Księżniczka - jeden z najwyższych tytułów przedstawicieli arystokracji, córka króla i królowej. Może również oznaczać:</p>", "Pei-Chen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Piusa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Pius</b>.</p><b>Pius</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „pobożny”, „cnotliwy”. Jako przydomek imię to po raz pierwszy pojawiło się u <a href=\"https://pl.wikipedia.org/wiki/Cesarze_rzymscy\" target=\"_blank\" rel=\"noopener noreferrer\">cesarza rzymskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Antoninus_Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina Piusa</a> (pan. 138–161). Imię to przyjęło dwunastu <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a>.", "Paula-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Paula</b>.</p><b>Paula</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Paweł</a>. W staropolskich dokumentach zapisano je około 1265 roku. Imię zyskało większą popularność w latach 80. i 90. XX wieku (pod wpływem języka angielskiego), kiedy liczba bieżących nadań przekroczyła 11 tysięcy. Od niej powstało imię <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Paulina</a> (obecnie bardziej popularne w Polsce – ma 224 173 nadania), dla której Paula może także służyć jako zdrobnienie.", "Phidan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fidan</b>.</p><p>Fidan to nazwisko kobiety pochodzące z Turcji, które oznacza \"sąpienie\". Słowo to ma jednak greckie korzenie.</p>", "Pei-Chi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Parwati": "<b>Parwati</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> <b>पार्वती</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tamilski\" target=\"_blank\" rel=\"noopener noreferrer\">tamilski</a>: <b>பார்வதி</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> Parvati) – <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> hinduistyczna reprezentująca łagodny aspekt <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aakti\" target=\"_blank\" rel=\"noopener noreferrer\">Śakti</a>, mocy boga <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>. Początkowo odrębna od innych plemiennych bogiń, w późniejszym <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> stopniowo przejmując niektóre ich atrybuty, często jest z nimi utożsamiana. Z biegiem czasu stała się uogólnioną personifikacją kobiecości, <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>, zwłaszcza w jej matczynym aspekcie jako Matadźi, czyli <a href=\"https://pl.wikipedia.org/wiki/Bogini_Matka\" target=\"_blank\" rel=\"noopener noreferrer\">Bogini Matka</a>. Często bywa łączona z <a href=\"https://pl.wikipedia.org/wiki/Saraswati\" target=\"_blank\" rel=\"noopener noreferrer\">Saraswati</a> i <a href=\"https://pl.wikipedia.org/wiki/Lakszmi\" target=\"_blank\" rel=\"noopener noreferrer\">Lakszmi</a> w trójcę bogiń, nazywaną <a href=\"https://pl.wikipedia.org/wiki/Tridewi\" target=\"_blank\" rel=\"noopener noreferrer\">Tridewi</a>. Bywa nazywana imieniem Arja.", "Pei-Yin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Pei-Yun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>", "Pi-Ju": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pi</b>.</p><b>&#960;</b> (czyt. <i>pi</i>), <b>ludolfina</b>, <b>stała Archimedesa</b> – <a href=\"https://pl.wikipedia.org/wiki/Stosunek_(matematyka)\" target=\"_blank\" rel=\"noopener noreferrer\">stosunek</a> <a href=\"https://pl.wikipedia.org/wiki/Obw%C3%B3d_(geometria)\" target=\"_blank\" rel=\"noopener noreferrer\">obwodu</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">koła</a> (czyli <a href=\"https://pl.wikipedia.org/wiki/D%C5%82ugo%C5%9B%C4%87_krzywej\" target=\"_blank\" rel=\"noopener noreferrer\">długości</a> <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%85g\" target=\"_blank\" rel=\"noopener noreferrer\">okręgu</a>) do długości jego <a href=\"https://pl.wikipedia.org/wiki/%C5%9Arednica\" target=\"_blank\" rel=\"noopener noreferrer\">średnicy</a>; stosunek ten jest niezależny od wielkości koła, bowiem wszystkie koła są do siebie <a href=\"https://pl.wikipedia.org/wiki/Podobie%C5%84stwo_(przekszta%C5%82cenie_geometryczne)\" target=\"_blank\" rel=\"noopener noreferrer\">podobne</a>. Liczba &#960; nazywana jest czasami <i>stałą Archimedesa</i> w uznaniu zasług <a href=\"https://pl.wikipedia.org/wiki/Archimedes\" target=\"_blank\" rel=\"noopener noreferrer\">Archimedesa z Syrakuz</a>, który jako pierwszy badał własności i znaczenie w matematyce tej liczby; określenie <i>ludolfina</i> pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ludolph_van_Ceulen\" target=\"_blank\" rel=\"noopener noreferrer\">Ludolpha van Ceulena</a>, który zyskał sławę, przedstawiając tę liczbę z dokładnością do 35 miejsc po przecinku. Grecy nie używali symbolu &#960; – wprowadził go dopiero <a href=\"https://pl.wikipedia.org/wiki/William_Jones_(matematyk)\" target=\"_blank\" rel=\"noopener noreferrer\">William Jones</a>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/Leonhard_Euler\" target=\"_blank\" rel=\"noopener noreferrer\">Leonhard Euler</a>.", "Pei-Yi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Pei</b>.</p><p>Pei to miasto w Tybecie, nazwane przez I. M.</p>"};
